/**
 * Helper to validate organizationId after multiTenantEnforcer middleware
 * Throws if organizationId is missing after tenant validation
 */
function requireOrgId(req: TenantRequest): number {
  if (!req.organizationId) {
    throw new Error('Organization ID is required but missing after tenant validation');
  }
  return req.organizationId;
}

/** UTC calendar date at midnight for consistent DOB checks */
function startOfTodayUtcDate(): Date {
  const d = new Date();
  return new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));
}

/** Parse YYYY-MM-DD as a UTC calendar date; invalid components return null */
function parseIsoDateOnlyUTC(value: string): Date | null {
  const s = String(value || "").trim();
  const m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(s);
  if (!m) return null;
  const y = parseInt(m[1], 10);
  const mo = parseInt(m[2], 10) - 1;
  const day = parseInt(m[3], 10);
  const dt = new Date(Date.UTC(y, mo, day));
  if (dt.getUTCFullYear() !== y || dt.getUTCMonth() !== mo || dt.getUTCDate() !== day) return null;
  return dt;
}

function ageYearsFromDobUTC(dob: Date): number {
  const today = startOfTodayUtcDate();
  let age = today.getUTCFullYear() - dob.getUTCFullYear();
  const m = today.getUTCMonth() - dob.getUTCMonth();
  if (m < 0 || (m === 0 && today.getUTCDate() < dob.getUTCDate())) age--;
  return age;
}

/** Next P###### id from existing numeric patient_id values in the org */
async function allocateNextDisplayPatientId(organizationId: number): Promise<string> {
  const r = await pool.query<{ n: string | null }>(
    `SELECT COALESCE(MAX(CAST(SUBSTRING(patient_id FROM 2) AS INTEGER)), 0)::text AS n
     FROM patients
     WHERE organization_id = $1 AND patient_id ~ '^P[0-9]+$'`,
    [organizationId],
  );
  const raw = r.rows[0]?.n;
  const max = raw ? parseInt(raw, 10) : 0;
  const next = Number.isFinite(max) ? max + 1 : 1;
  return `P${next.toString().padStart(6, "0")}`;
}

/**
 * Security helper: Enforces created_by field with logged-in user ID
 * Prevents client from spoofing creator identity
 * @param req - Request with authenticated user
 * @param payload - Data object to modify
 * @param fieldName - Name of the created_by field (varies by module)
 * @returns Modified payload with enforced created_by field
 */
function enforceCreatedBy<T extends Record<string, any>>(
  req: TenantRequest,
  payload: T,
  fieldName: string = 'createdBy'
): T {
  if (!req.user?.id) {
    throw new Error('User authentication required to set creator');
  }
  // Always overwrite client-provided value with server-side user ID
  return {
    ...payload,
    [fieldName]: req.user.id
  };
}

/**
 * Helper function to ensure directory exists, creates it if it doesn't
 * @param dirPath - The directory path to check/create
 * @returns Promise<boolean> - true if directory exists or was created, false on error
 */
async function ensureDirectoryExists(dirPath: string): Promise<boolean> {
  try {
    await fs.promises.access(dirPath);
    return true; // Directory already exists
  } catch {
    try {
      await fs.promises.mkdir(dirPath, { recursive: true });
      console.log(`📁 Created directory: ${dirPath}`);
      return true; // Directory created successfully
    } catch (error) {
      console.error(`❌ Failed to create directory ${dirPath}:`, error);
      return false; // Failed to create directory
    }
  }
}

