  app.patch("/api/organization/settings", authMiddleware, requireRole(["admin", "doctor", "nurse"]), async (req: TenantRequest, res) => {
    try {
      if (!req.tenant || !req.tenant.id) {
        console.error("[ORG-SETTINGS] No tenant found in request");
        return res.status(400).json({ error: "Tenant context required" });
      }

      console.log("[ORG-SETTINGS] Request body:", JSON.stringify(req.body, null, 2));
      console.log("[ORG-SETTINGS] Tenant ID:", req.tenant.id);

      const updateData = z.object({
        name: z.string().optional(),
        brandName: z.string().optional(),
        region: z.string().optional(),
        settings: z.object({
          theme: z.object({
            primaryColor: z.string().optional(),
            logoUrl: z.string().optional()
          }).optional(),
          compliance: z.object({
            gdprEnabled: z.boolean().optional()
          }).optional(),
          features: z.object({
            aiEnabled: z.boolean().optional(),
            billingEnabled: z.boolean().optional()
          }).optional()
        }).optional()
      }).parse(req.body);

      // Get existing organization to merge settings if needed
      let finalUpdateData: any = { ...updateData };

      // Only merge settings if settings are being updated
      if (updateData.settings) {
        const existingOrg = await storage.getOrganization(req.tenant.id);
        if (!existingOrg) {
          return res.status(404).json({ error: "Organization not found" });
        }

        const existingSettings = (existingOrg.settings as any) || {};
        finalUpdateData.settings = {
          ...existingSettings,
          ...updateData.settings,
          theme: updateData.settings.theme ? {
            ...(existingSettings.theme || {}),
            ...updateData.settings.theme,
          } : existingSettings.theme,
          compliance: updateData.settings.compliance ? {
            ...(existingSettings.compliance || {}),
            ...updateData.settings.compliance,
          } : existingSettings.compliance,
          features: updateData.settings.features ? {
            ...(existingSettings.features || {}),
            ...updateData.settings.features,
          } : existingSettings.features,
        };
      }

      console.log("[ORG-SETTINGS] Final update data:", JSON.stringify(finalUpdateData, null, 2));

      const updatedOrganization = await storage.updateOrganization(req.tenant.id, finalUpdateData);

      if (!updatedOrganization) {
        return res.status(404).json({ error: "Organization not found" });
      }

      console.log("[ORG-SETTINGS] Update successful, returning:", JSON.stringify(updatedOrganization, null, 2));

      // Ensure brandName is included in the response
      const response = {
        ...updatedOrganization,
        brandName: updatedOrganization.brandName || updatedOrganization.name
      };

      res.json(response);
    } catch (error: any) {
      console.error("[ORG-SETTINGS] Error:", error);
      console.error("[ORG-SETTINGS] Error name:", error?.name);
      console.error("[ORG-SETTINGS] Error message:", error?.message);
      console.error("[ORG-SETTINGS] Error stack:", error?.stack);
      console.error("[ORG-SETTINGS] Request body:", JSON.stringify(req.body, null, 2));
      console.error("[ORG-SETTINGS] Tenant:", req.tenant?.id);

      // Check if it's a Zod validation error
      if (error.name === 'ZodError') {
        return res.status(400).json({
          error: "Invalid request data",
          details: error.errors
        });
      }

      // Return more detailed error information
      const errorResponse: any = {
        error: "Failed to update organization settings",
        message: error.message || "Unknown error"
      };

      // Include validation errors if it's a Zod error
      if (error.name === 'ZodError' && error.errors) {
        errorResponse.validationErrors = error.errors;
      }

      // Include database error details in development
      if (process.env.NODE_ENV === 'development' || process.env.NODE_ENV !== 'production') {
        errorResponse.details = {
          code: error.code,
          constraint: error.constraint,
          table: error.table,
          detail: error.detail
        };
      }

      res.status(500).json(errorResponse);
    }
  });

  // QuickBooks OAuth - get authorization URL to open in popup (requires auth so we have org for state)
  app.get("/api/quickbooks/auth/url", authMiddleware, async (req: TenantRequest, res) => {
    try {
      const clientId = process.env.QUICKBOOKS_CLIENT_ID;
      if (!clientId) {
        return res.status(503).json({
          error: "QuickBooks is not configured",
          message: "Missing QUICKBOOKS_CLIENT_ID. Add QuickBooks credentials in environment variables.",
        });
      }
      const organizationId = req.tenant?.id ?? req.user?.organizationId;
      if (!organizationId) {
        return res.status(400).json({ error: "Organization context required" });
      }
      const redirectUri = process.env.QUICKBOOKS_REDIRECT_URI
        || (process.env.REPLIT_DEV_DOMAIN ? `https://${process.env.REPLIT_DEV_DOMAIN}` : "http://localhost:5000") + "/api/quickbooks/auth/callback";
      const scope = "com.intuit.quickbooks.accounting";
      const state = Buffer.from(JSON.stringify({ orgId: organizationId })).toString("base64");
      const params = new URLSearchParams({
        client_id: clientId,
        redirect_uri: redirectUri,
        response_type: "code",
        scope,
        state,
      });
      const url = `https://appcenter.intuit.com/connect/oauth2?${params.toString()}`;
      return res.json({ url });
    } catch (err: any) {
      console.error("[QUICKBOOKS] Auth URL error:", err);
      return res.status(500).json({ error: err.message || "Failed to build QuickBooks authorization URL" });
    }
  });

  // QuickBooks OAuth callback - MUST be before authMiddleware since OAuth popup has no session
  app.get("/api/quickbooks/auth/callback", tenantMiddleware, async (req: TenantRequest, res) => {
    try {
      console.log("[QUICKBOOKS] OAuth callback received!");
      const { code, realmId, state } = req.query;

      if (!code || !realmId) {
        console.log("[QUICKBOOKS] Missing code or realmId");
        return res.status(400).send(`
          <html>
            <body>
              <h1>Error: Invalid OAuth callback</h1>
              <p>Missing required parameters</p>
            </body>
          </html>
        `);
      }

      console.log("[QUICKBOOKS] Code:", code);
      console.log("[QUICKBOOKS] Realm ID:", realmId);
      console.log("[QUICKBOOKS] State:", state);

      // Extract organization ID from state parameter
      let organizationId: number | undefined;
      if (state) {
        try {
          const stateData = JSON.parse(Buffer.from(state as string, 'base64').toString());
          organizationId = stateData.orgId;
          console.log("[QUICKBOOKS] Extracted orgId from state:", organizationId);
        } catch (e) {
          console.log("[QUICKBOOKS] Failed to parse state, falling back to tenant context");
        }
      }

      // Fallback to tenant context if state parsing failed
      if (!organizationId) {
        organizationId = req.tenant?.id;
      }

      if (!organizationId) {
        throw new Error("Organization ID not found in state or tenant context");
      }

      // Exchange authorization code for access and refresh tokens manually
      const redirectUri = process.env.QUICKBOOKS_REDIRECT_URI || `${process.env.REPLIT_DEV_DOMAIN ? `https://${process.env.REPLIT_DEV_DOMAIN}` : 'http://localhost:5000'}/api/quickbooks/auth/callback`;

      console.log("[QUICKBOOKS] Exchanging authorization code for tokens...");
      console.log("[QUICKBOOKS] Redirect URI:", redirectUri);

      // Manually exchange token using axios
      const axios = (await import('axios')).default;
      const authHeader = Buffer.from(`${process.env.QUICKBOOKS_CLIENT_ID}:${process.env.QUICKBOOKS_CLIENT_SECRET}`).toString('base64');

      const requestBody = `grant_type=authorization_code&code=${encodeURIComponent(code as string)}&redirect_uri=${encodeURIComponent(redirectUri)}`;
      console.log("[QUICKBOOKS] Request body length:", requestBody.length);

      const tokenResponse = await axios.post(
        'https://oauth.platform.intuit.com/oauth2/v1/tokens/bearer',
        requestBody,
        {
          headers: {
            'Accept': 'application/json',
            'Content-Type': 'application/x-www-form-urlencoded',
            'Authorization': `Basic ${authHeader}`,
          },
        }
      );

      const token = tokenResponse.data;

      console.log("[QUICKBOOKS] Token exchange successful!");
      console.log("[QUICKBOOKS] Access token received:", !!token.access_token);
      console.log("[QUICKBOOKS] Refresh token received:", !!token.refresh_token);
      console.log("[QUICKBOOKS] Expires in:", token.expires_in, "seconds");

      console.log("[QUICKBOOKS] Saving connection to database for organization:", organizationId);

      // Check if connection already exists
      const existingConnection = await db.select()
        .from(quickbooksConnections)
        .where(and(
          eq(quickbooksConnections.organizationId, organizationId),
          eq(quickbooksConnections.realmId, realmId as string)
        ))
        .limit(1);

      // Determine baseUrl based on environment
      const baseUrl = process.env.QUICKBOOKS_ENVIRONMENT === 'production'
        ? 'https://quickbooks.api.intuit.com'
        : 'https://sandbox-quickbooks.api.intuit.com';

      if (existingConnection.length > 0) {
        // Update existing connection
        console.log("[QUICKBOOKS] Updating existing connection");
        await db.update(quickbooksConnections)
          .set({
            accessToken: token.access_token,
            refreshToken: token.refresh_token,
            tokenExpiry: new Date(Date.now() + (token.expires_in * 1000)),
            isActive: true,
          })
          .where(eq(quickbooksConnections.id, existingConnection[0].id));
      } else {
        // Create new connection
        console.log("[QUICKBOOKS] Creating new connection");
        await db.insert(quickbooksConnections).values({
          organizationId,
          companyId: realmId as string, // Use realmId as companyId
          companyName: "QuickBooks Company", // Placeholder - will be updated after fetching company info
          realmId: realmId as string,
          accessToken: token.access_token,
          refreshToken: token.refresh_token,
          tokenExpiry: new Date(Date.now() + (token.expires_in * 1000)),
          baseUrl,
          isActive: true,
          syncSettings: {},
        });
      }

      console.log("[QUICKBOOKS] Connection saved successfully!");
      console.log("[QUICKBOOKS] About to send HTML response...");

      // Set proper headers to prevent caching and ensure HTML rendering
      res.setHeader('Content-Type', 'text/html; charset=utf-8');
      res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate');
      res.setHeader('X-Frame-Options', 'SAMEORIGIN');
      console.log("[QUICKBOOKS] Headers set, building HTML...");

      const successHtml = `<!DOCTYPE html>
        <html>
          <head>
            <title>QuickBooks Connected</title>
            <style>
              body {
                font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
                display: flex;
                align-items: center;
                justify-content: center;
                min-height: 100vh;
                margin: 0;
                background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
              }
              .success-container {
                background: white;
                padding: 3rem;
                border-radius: 16px;
                box-shadow: 0 20px 60px rgba(0,0,0,0.3);
                text-align: center;
                max-width: 400px;
              }
              .checkmark {
                width: 80px;
                height: 80px;
                border-radius: 50%;
                background: #10b981;
                margin: 0 auto 1.5rem;
                display: flex;
                align-items: center;
                justify-content: center;
                animation: scaleIn 0.5s ease-out;
              }
              @keyframes scaleIn {
                from { transform: scale(0); }
                to { transform: scale(1); }
              }
              .checkmark svg {
                width: 50px;
                height: 50px;
                stroke: white;
                stroke-width: 3;
                fill: none;
                stroke-linecap: round;
                stroke-dasharray: 60;
                stroke-dashoffset: 60;
                animation: drawCheck 0.5s ease-out 0.3s forwards;
              }
              @keyframes drawCheck {
                to { stroke-dashoffset: 0; }
              }
              h1 {
                color: #10b981;
                font-size: 1.75rem;
                margin: 0 0 0.5rem;
              }
              p {
                color: #6b7280;
                margin: 0.5rem 0;
                line-height: 1.5;
              }
              .realm-id {
                font-family: monospace;
                background: #f3f4f6;
                padding: 0.5rem 1rem;
                border-radius: 8px;
                margin-top: 1rem;
                font-size: 0.875rem;
                color: #4b5563;
              }
            </style>
          </head>
          <body>
            <div class="success-container">
              <div class="checkmark">
                <svg viewBox="0 0 52 52">
                  <path d="M14 27l9 9 19-19" />
                </svg>
              </div>
              <h1>Successfully Connected!</h1>
              <p>Your QuickBooks account has been linked to emrSoft.</p>
              <div class="realm-id">Realm ID: ${realmId}</div>
            </div>
            <script>
              // Send message to parent window immediately (no console.log to avoid wrapping)
              if (window.parent && window.parent !== window) {
                window.parent.postMessage({ type: 'quickbooks-connected', realmId: '${realmId}' }, '*');
                // Log after sending to confirm
                setTimeout(() => console.log('[QB CALLBACK] Message sent to parent, realmId: ${realmId}'), 100);
              }
              // Fallback for popup window
              else if (window.opener) {
                window.opener.postMessage({ type: 'quickbooks-connected', realmId: '${realmId}' }, '*');
                window.close();
              }
            </script>
          </body>
        </html>`;

      console.log("[QUICKBOOKS] HTML length:", successHtml.length);
      console.log("[QUICKBOOKS] Sending response now...");
      res.send(successHtml);
      console.log("[QUICKBOOKS] Response sent successfully!");
    } catch (error) {
      console.error("[QUICKBOOKS] Error handling OAuth callback:", error);
      res.status(500).json({ error: "Failed to handle OAuth callback" });
    }
  });

  // Serve static files from uploads folder (public read-only access)
