  // Get current organization's subscription (latest subscription, check expiration on client)
  app.get("/api/subscriptions/current", authMiddleware, requireRole(["admin"]), async (req: TenantRequest, res) => {
    try {
      // Invoices are scoped by organization_id. Prefer orgId from the JWT (most reliable),
      // fallback to tenant id (some deployments equate tenant.id to organization id).
      const organizationId = (req.user as any)?.organizationId ?? req.tenant!.id;

      // Query the database for the latest subscription (ordered by createdAt DESC) regardless of expiration
      const result = await db
        .select({
          id: saasSubscriptions.id,
          organizationId: saasSubscriptions.organizationId,
          packageId: saasSubscriptions.packageId,
          plan: saasPackages.name,
          planName: saasPackages.name,
          status: saasSubscriptions.status,
          paymentStatus: saasSubscriptions.paymentStatus,
          userLimit: saasSubscriptions.maxUsers,
          monthlyPrice: saasPackages.price,
          trialEndsAt: saasSubscriptions.trialEnd,
          currentPeriodStart: saasSubscriptions.currentPeriodStart,
          nextBillingAt: saasSubscriptions.currentPeriodEnd,
          expiresAt: saasSubscriptions.expiresAt,
          stripeSubscriptionId: saasSubscriptions.stripeSubscriptionId,
          features: saasPackages.features,
          createdAt: saasSubscriptions.createdAt,
          updatedAt: saasSubscriptions.updatedAt,
        })
        .from(saasSubscriptions)
        .leftJoin(saasPackages, eq(saasSubscriptions.packageId, saasPackages.id))
        .where(eq(saasSubscriptions.organizationId, organizationId))
        .orderBy(desc(saasSubscriptions.createdAt))
        .limit(1);

      if (result.length === 0) {
        return res.status(404).json({ error: "No subscription found for this organization" });
      }

      // Count actual users in the organization (excluding SaaS owners and patient role)
      const userCountResult = await db
        .select({ count: sql<number>`count(*)::int` })
        .from(users)
        .where(and(
          eq(users.organizationId, organizationId),
          eq(users.isSaaSOwner, false),
          ne(users.role, 'patient') // Exclude patient role - patients are counted separately
        ));

      const actualUserCount = userCountResult[0]?.count || 0;

      // Count actual patients in the organization
      const patientCountResult = await db
        .select({ count: sql<number>`count(*)::int` })
        .from(patients)
        .where(eq(patients.organizationId, organizationId));

      const actualPatientCount = patientCountResult[0]?.count || 0;

      // Get maxUsers and maxPatients from package features
      const packageFeatures = result[0].features as any || {};
      const maxUsers = packageFeatures.maxUsers || result[0].userLimit || 0;
      const maxPatients = packageFeatures.maxPatients || 0;

      // Return subscription with actual counts and limits
      res.json({
        ...result[0],
        currentUsers: actualUserCount,
        currentPatients: actualPatientCount,
        userLimit: maxUsers,
        features: {
          ...packageFeatures,
          maxUsers: maxUsers,
          maxPatients: maxPatients
        }
      });
    } catch (error) {
      console.error("Subscription fetch error:", error);
      res.status(500).json({ error: "Failed to fetch subscription" });
    }
  });

  // Get billing history (payment history) for current organization
  app.get("/api/billing-history", authMiddleware, requireRole(["admin"]), async (req: TenantRequest, res) => {
    try {
      // Invoices are scoped by organization_id. In some environments `req.user.organizationId`
      // and `req.tenant.id` can differ, so try both to avoid false "not found".
      const orgIdsRaw = [(req.user as any)?.organizationId, req.tenant?.id];
      const organizationIds = Array.from(
        new Set(
          orgIdsRaw
            .map((v) => (v == null ? NaN : Number(v)))
            .filter((n) => Number.isFinite(n))
        )
      ) as number[];
      if (organizationIds.length === 0) {
        return res.status(400).json({ error: "Organization ID is required" });
      }
      const { saasPayments } = await import("../shared/schema");

      // Get the latest subscription's expiresAt to use as invoice end date
      const latestSubscription = await db
        .select({
          expiresAt: saasSubscriptions.expiresAt,
        })
        .from(saasSubscriptions)
        .where(eq(saasSubscriptions.organizationId, organizationId))
        .orderBy(desc(saasSubscriptions.createdAt))
        .limit(1);

      const invoiceEndDate = latestSubscription.length > 0 && latestSubscription[0].expiresAt
        ? (latestSubscription[0].expiresAt instanceof Date 
            ? latestSubscription[0].expiresAt.toISOString() 
            : new Date(latestSubscription[0].expiresAt).toISOString())
        : null;

      // Get payments
      const payments = await db
        .select()
        .from(saasPayments)
        .where(eq(saasPayments.organizationId, organizationId))
        .orderBy(desc(saasPayments.paymentDate));

      // Format dates as UTC ISO strings to ensure no timezone conversion
      // Use subscription.expiresAt as invoice end date for all invoices
      const formattedPayments = payments.map(payment => ({
        ...payment,
        paymentDate: payment.paymentDate 
          ? (payment.paymentDate instanceof Date 
              ? payment.paymentDate.toISOString() 
              : new Date(payment.paymentDate).toISOString())
          : null,
        dueDate: payment.dueDate 
          ? (payment.dueDate instanceof Date 
              ? payment.dueDate.toISOString() 
              : new Date(payment.dueDate).toISOString())
          : null,
        periodStart: payment.periodStart 
          ? (payment.periodStart instanceof Date 
              ? payment.periodStart.toISOString() 
              : new Date(payment.periodStart).toISOString())
          : null,
        periodEnd: payment.periodEnd 
          ? (payment.periodEnd instanceof Date 
              ? payment.periodEnd.toISOString() 
              : new Date(payment.periodEnd).toISOString())
          : null,
        expiresAt: invoiceEndDate, // Invoice end date from latest subscription
        createdAt: payment.createdAt instanceof Date 
          ? payment.createdAt.toISOString() 
          : payment.createdAt,
        updatedAt: payment.updatedAt instanceof Date 
          ? payment.updatedAt.toISOString() 
          : payment.updatedAt,
      }));

      res.json(formattedPayments);
    } catch (error) {
      console.error("Billing history fetch error:", error);
      res.status(500).json({ error: "Failed to fetch billing history" });
    }
  });

  // Download billing invoice PDF for a specific payment
  app.get("/api/billing-history/:paymentId/invoice", authMiddleware, requireRole(["admin"]), async (req: TenantRequest, res) => {
    try {
      const organizationId = req.tenant!.id;
      const paymentId = parseInt(req.params.paymentId);
      const { saasPayments, saasSubscriptions, saasPackages, organizations } = await import("../shared/schema");

      // Get payment record
      const [payment] = await db
        .select()
        .from(saasPayments)
        .where(and(
          eq(saasPayments.id, paymentId),
          eq(saasPayments.organizationId, organizationId)
        ));

      if (!payment) {
        return res.status(404).json({ error: "Payment not found" });
      }

      // Get organization details
      const [org] = await db
        .select()
        .from(organizations)
        .where(eq(organizations.id, organizationId));

      // Get subscription and package details
      let packageName = "Subscription";
      if (payment.subscriptionId) {
        const [subscription] = await db
          .select()
          .from(saasSubscriptions)
          .where(eq(saasSubscriptions.id, payment.subscriptionId));

        if (subscription?.packageId) {
          const [pkg] = await db
            .select()
            .from(saasPackages)
            .where(eq(saasPackages.id, subscription.packageId));
          if (pkg) {
            packageName = pkg.name;
          }
        }
      }

      // Generate PDF using pdf-lib
      const { PDFDocument, rgb, StandardFonts } = await import('pdf-lib');
      const pdfDoc = await PDFDocument.create();
      const page = pdfDoc.addPage([595, 842]); // A4 size
      const { width, height } = page.getSize();

      const font = await pdfDoc.embedFont(StandardFonts.Helvetica);
      const boldFont = await pdfDoc.embedFont(StandardFonts.HelveticaBold);

      const darkText = rgb(0.1, 0.1, 0.1);
      const mutedText = rgb(0.4, 0.4, 0.4);
      const primaryBlue = rgb(0.2, 0.4, 0.8);

      let yPosition = height - 50;

      // Header
      page.drawText('INVOICE', {
        x: 50,
        y: yPosition,
        size: 28,
        font: boldFont,
        color: primaryBlue
      });

      page.drawText(payment.invoiceNumber, {
        x: width - 200,
        y: yPosition,
        size: 14,
        font: boldFont,
        color: darkText
      });

      yPosition -= 40;

      // Invoice details
      page.drawText(`Date: ${payment.paymentDate ? new Date(payment.paymentDate).toLocaleDateString('en-GB') : new Date().toLocaleDateString('en-GB')}`, {
        x: 50,
        y: yPosition,
        size: 10,
        font,
        color: mutedText
      });

      page.drawText(`Status: ${payment.paymentStatus.toUpperCase()}`, {
        x: width - 200,
        y: yPosition,
        size: 10,
        font,
        color: payment.paymentStatus === 'completed' ? rgb(0.1, 0.6, 0.1) : mutedText
      });

      yPosition -= 40;

      // Bill To section
      page.drawText('Bill To:', {
        x: 50,
        y: yPosition,
        size: 12,
        font: boldFont,
        color: darkText
      });

      yPosition -= 18;

      page.drawText(org?.name || 'Organization', {
        x: 50,
        y: yPosition,
        size: 11,
        font,
        color: darkText
      });

      yPosition -= 50;

      // Line separator
      page.drawLine({
        start: { x: 50, y: yPosition },
        end: { x: width - 50, y: yPosition },
        thickness: 1,
        color: rgb(0.85, 0.85, 0.85)
      });

      yPosition -= 30;

      // Table header
      page.drawText('Description', {
        x: 50,
        y: yPosition,
        size: 10,
        font: boldFont,
        color: mutedText
      });

      page.drawText('Period', {
        x: 250,
        y: yPosition,
        size: 10,
        font: boldFont,
        color: mutedText
      });

      page.drawText('Amount', {
        x: width - 100,
        y: yPosition,
        size: 10,
        font: boldFont,
        color: mutedText
      });

      yPosition -= 25;

      // Table row
      page.drawText(packageName, {
        x: 50,
        y: yPosition,
        size: 11,
        font,
        color: darkText
      });

      const periodStart = new Date(payment.periodStart).toLocaleDateString('en-GB', { day: '2-digit', month: 'short' });
      const periodEnd = new Date(payment.periodEnd).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
      page.drawText(`${periodStart} - ${periodEnd}`, {
        x: 250,
        y: yPosition,
        size: 11,
        font,
        color: darkText
      });

      page.drawText(`${payment.currency} ${parseFloat(payment.amount).toFixed(2)}`, {
        x: width - 100,
        y: yPosition,
        size: 11,
        font: boldFont,
        color: darkText
      });

      yPosition -= 40;

      // Line separator
      page.drawLine({
        start: { x: 50, y: yPosition },
        end: { x: width - 50, y: yPosition },
        thickness: 1,
        color: rgb(0.85, 0.85, 0.85)
      });

      yPosition -= 25;

      // Total
      page.drawText('Total:', {
        x: width - 180,
        y: yPosition,
        size: 12,
        font: boldFont,
        color: darkText
      });

      page.drawText(`${payment.currency} ${parseFloat(payment.amount).toFixed(2)}`, {
        x: width - 100,
        y: yPosition,
        size: 14,
        font: boldFont,
        color: primaryBlue
      });

      yPosition -= 40;

      // Payment method
      page.drawText(`Payment Method: ${payment.paymentMethod.replace('_', ' ').toUpperCase()}`, {
        x: 50,
        y: yPosition,
        size: 10,
        font,
        color: mutedText
      });

      // Footer
      page.drawText('Thank you for your business!', {
        x: 50,
        y: 80,
        size: 10,
        font,
        color: mutedText
      });

      let pdfBytes = await pdfDoc.save();

      res.setHeader('Content-Type', 'application/pdf');
      res.setHeader('Content-Disposition', `attachment; filename="${payment.invoiceNumber}.pdf"`);
      res.send(Buffer.from(pdfBytes));
    } catch (error) {
      console.error("Invoice download error:", error);
      res.status(500).json({ error: "Failed to generate invoice" });
    }
  });

  // Get search suggestions for billing search
  app.get("/api/billing/search-suggestions", authMiddleware, async (req: TenantRequest, res) => {
    try {
      const query = (req.query.query as string || "").toLowerCase().trim();

      if (query.length < 2) {
        return res.json([]);
      }

      const organizationId = req.tenant!.id;

      // Query invoices for suggestions
      const invoices = await db
        .select({
          invoiceNumber: schema.invoices.invoiceNumber,
          patientId: schema.invoices.patientId,
          patientName: schema.invoices.patientName,
        })
        .from(schema.invoices)
        .where(
          and(
            eq(schema.invoices.organizationId, organizationId),
            or(
              sql`LOWER(${schema.invoices.invoiceNumber}) LIKE ${`%${query}%`}`,
              sql`LOWER(CAST(${schema.invoices.patientId} AS TEXT)) LIKE ${`%${query}%`}`,
              sql`LOWER(${schema.invoices.patientName}) LIKE ${`%${query}%`}`
            )
          )
        )
        .limit(30);

      // Build suggestions array with deduplication
      const suggestions: Array<{
        type: 'invoice_id' | 'patient_id' | 'patient_name';
        value: string;
        display: string;
        searchValue: string;
      }> = [];

      const seenValues = new Set<string>();

      // Add invoice number suggestions
      invoices.forEach(inv => {
        if (inv.invoiceNumber && inv.invoiceNumber.toLowerCase().includes(query)) {
          const key = `invoice:${inv.invoiceNumber}`;
          if (!seenValues.has(key)) {
            seenValues.add(key);
            suggestions.push({
              type: 'invoice_id',
              value: inv.invoiceNumber,
              display: `Invoice: ${inv.invoiceNumber}`,
              searchValue: inv.invoiceNumber
            });
          }
        }
      });

      // Add patient ID suggestions
      invoices.forEach(inv => {
        if (inv.patientId && String(inv.patientId).toLowerCase().includes(query)) {
          const key = `patient_id:${inv.patientId}`;
          if (!seenValues.has(key)) {
            seenValues.add(key);
            suggestions.push({
              type: 'patient_id',
              value: String(inv.patientId),
              display: `Patient ID: ${inv.patientId}`,
              searchValue: String(inv.patientId)
            });
          }
        }
      });

      // Add patient name suggestions
      invoices.forEach(inv => {
        if (inv.patientName && inv.patientName.toLowerCase().includes(query)) {
          const key = `patient_name:${inv.patientName}`;
          if (!seenValues.has(key)) {
            seenValues.add(key);
            suggestions.push({
              type: 'patient_name',
              value: inv.patientName,
              display: `Patient: ${inv.patientName}`,
              searchValue: inv.patientName
            });
          }
        }
      });

      // Return top 10 suggestions
      res.json(suggestions.slice(0, 10));
    } catch (error) {
      console.error("Search suggestions fetch error:", error);
      res.status(500).json({ error: "Failed to fetch search suggestions" });
    }
  });

