  app.get("/api/patients", authMiddleware, requireRole(["admin", "doctor", "nurse", "patient"]), async (req: TenantRequest, res) => {
    try {
      const orgId = req.tenant?.id ?? req.user?.organizationId;
      if (!orgId) {
        return res.status(400).json({ error: "Organization context required" });
      }

      // No default limit: return all patients so count (e.g. "12 patients found") is accurate for doctor/nurse/admin
      const limitParam = req.query.limit as string;
      const limit = limitParam !== undefined && limitParam !== '' ? parseInt(limitParam, 10) : undefined;
      const isActiveParam = req.query.isActive as string;

      // Parse isActive parameter: if provided, convert to boolean, otherwise undefined (return all)
      let isActive: boolean | undefined = undefined;
      if (isActiveParam !== undefined) {
        isActive = isActiveParam === 'true';
      }

      const patients = await storage.getPatientsByOrganization(orgId, limit, isActive);
      const userIds = [
        ...new Set(
          patients
            .map((p) => p.userId)
            .filter((id): id is number => typeof id === "number" && id > 0),
        ),
      ];
      if (userIds.length > 0) {
        const userRows = await db
          .select({ id: users.id, email: users.email })
          .from(users)
          .where(and(eq(users.organizationId, orgId), inArray(users.id, userIds)));
        const emailByUserId = new Map<number, string>();
        for (const u of userRows) {
          const em = u.email?.trim();
          if (em) emailByUserId.set(u.id, em);
        }
        for (const p of patients as Array<{ userId?: number | null; linkedUserEmail?: string | null }>) {
          if (typeof p.userId === "number" && emailByUserId.has(p.userId)) {
            p.linkedUserEmail = emailByUserId.get(p.userId) ?? null;
          }
        }
      }
      res.json(patients);
    } catch (error) {
      console.error("Patients fetch error:", error);
      res.status(500).json({ error: "Failed to fetch patients" });
    }
  });

  /** Plaintext patient emails for form-share recipient picker (org-scoped, deduped). */
  app.get(
    "/api/patients/share-recipient-emails",
    authMiddleware,
    requireRole(["admin", "doctor", "nurse"]),
    async (req: TenantRequest, res) => {
      try {
        const orgId = req.tenant!.id;
        const patients = await storage.getPatientsByOrganization(orgId, undefined, true);
        const userIds = [
          ...new Set(
            patients
              .map((p) => p.userId)
              .filter((id): id is number => typeof id === "number" && id > 0),
          ),
        ];
        const emailByUserId = new Map<number, string>();
        if (userIds.length > 0) {
          const userRows = await db
            .select({ id: users.id, email: users.email })
            .from(users)
            .where(and(eq(users.organizationId, orgId), inArray(users.id, userIds)));
          for (const u of userRows) {
            const em = u.email?.trim();
            if (em && em.includes("@")) emailByUserId.set(u.id, em);
          }
        }

        const seen = new Set<string>();
        const recipients: Array<{ patientId: number; email: string }> = [];
        const pushEmail = (patientId: number, raw: string | null | undefined) => {
          const email = typeof raw === "string" ? raw.trim() : "";
          if (!email.includes("@") || email.startsWith("{")) return;
          const key = email.toLowerCase();
          if (seen.has(key)) return;
          seen.add(key);
          recipients.push({ patientId, email });
        };

        for (const p of patients) {
          pushEmail(p.id, p.email);
          if (typeof p.userId === "number" && emailByUserId.has(p.userId)) {
            pushEmail(p.id, emailByUserId.get(p.userId));
          }
        }

        recipients.sort((a, b) => a.email.localeCompare(b.email, undefined, { sensitivity: "base" }));
        res.json(recipients);
      } catch (error) {
        console.error("Share recipient emails fetch error:", error);
        res.status(500).json({ error: "Failed to fetch patient emails" });
      }
    },
  );

