  app.get("/api/users/check-subscription-limit", authMiddleware, async (req: TenantRequest, res) => {
    try {
      const organizationId = req.tenant!.id;

      // Get active subscription for the organization using storage.getSubscription()
      // This method already filters by expiresAt (only returns subscriptions where expiresAt > current date)
      const subscription = await storage.getSubscription(organizationId);

      if (!subscription) {
        return res.status(403).json({
          error: "No active subscription found for this organization",
          canCreateUser: false
        });
      }

      // Extract maxUsers and maxPatients from subscription
      // subscription.userLimit comes from saasSubscriptions.maxUsers column
      // subscription.maxPatients comes from saasSubscriptions.maxPatients column (now included in getSubscription return)
      const packageFeatures = subscription.features as any || {};
      const maxUsers = subscription.userLimit || packageFeatures.maxUsers || 0;
      const maxPatients = (subscription as any).maxPatients || packageFeatures.maxPatients || 0;
      
      console.log('[check-subscription-limit] Subscription limits:', {
        userLimit_from_subscription: subscription.userLimit,
        maxPatients_from_subscription: (subscription as any).maxPatients,
        maxUsers_from_features: packageFeatures.maxUsers,
        maxPatients_from_features: packageFeatures.maxPatients,
        final_maxUsers: maxUsers,
        final_maxPatients: maxPatients
      });

      // Count existing non-patient users for the organization
      // Exclude SaaS owners, inactive users, and patient role
      const [nonPatientUserCount] = await db.select({
        count: sql<number>`count(*)::int`
      })
        .from(users)
        .where(
          and(
            eq(users.organizationId, organizationId),
            ne(users.role, 'patient'),
            eq(users.isSaaSOwner, false),
            eq(users.isActive, true)
          )
        );

      // Count existing patients (users with role='patient')
      const [patientCount] = await db.select({
        count: sql<number>`count(*)::int`
      })
        .from(users)
        .where(
          and(
            eq(users.organizationId, organizationId),
            eq(users.role, 'patient'),
            eq(users.isActive, true)
          )
        );

      const currentUserCount = nonPatientUserCount?.count || 0;
      const remainingUsers = maxUsers - currentUserCount;

      const currentPatientCount = patientCount?.count || 0;
      const remainingPatients = maxPatients - currentPatientCount;

      res.json({
        canCreateUser: remainingUsers > 0,
        maxUsers,
        currentUserCount,
        remainingUsers,
        maxPatients,
        currentPatientCount,
        remainingPatients,
        subscriptionStatus: subscription.status,
        planName: subscription.planName || subscription.plan || 'N/A',
        expiresAt: subscription.expiresAt ? new Date(subscription.expiresAt).toISOString() : null
      });
    } catch (error) {
      console.error("Error checking subscription limit:", error);
      res.status(500).json({ error: "Failed to check subscription limit" });
    }
  });

  app.post("/api/users", authMiddleware, requireRole(["admin"]), async (req: TenantRequest, res) => {
    try {
      console.log("Creating user with role-based permissions");
      console.log("Request body:", req.body);

      const userData = z.object({
        email: z.string().email(),
        username: z.string().min(3),
        password: z.string().min(6),
        firstName: z.string().min(1),
        lastName: z.string().min(1),
        role: z.string().min(1), // Accept any role from database
        professionalRegistrationId: z.string().optional(),
        department: z.string().optional(),
        medicalSpecialtyCategory: z.string().optional(),
        subSpecialty: z.string().optional(),
        workingDays: z.array(z.string()).optional(),
        workingHours: z.object({ start: z.string().optional(), end: z.string().optional() }).optional(),
        // Date of Birth and Gender at Birth (stored on users table for all roles)
        dateOfBirth: z.string().optional(),
        genderAtBirth: z.string().optional(),
        // Patient-specific fields
        phone: z.string().optional(),
        nhsNumber: z.string().optional(),
        address: z.object({
          street: z.string().optional(),
          city: z.string().optional(),
          state: z.string().optional(),
          postcode: z.string().optional(),
          country: z.string().optional(),
        }).optional(),
        emergencyContact: z.object({
          name: z.string().optional(),
          relationship: z.string().optional(),
          phone: z.string().optional(),
          email: z.string().optional(),
        }).optional(),
        insuranceInfo: z.object({
          provider: z.string().optional(),
          policyNumber: z.string().optional(),
          memberNumber: z.string().optional(),
          planType: z.string().optional(),
          effectiveDate: z.string().optional(),
        }).optional(),
      }).superRefine((data, ctx) => {
        if (data.role !== 'patient' && (!data.professionalRegistrationId || data.professionalRegistrationId.trim() === "")) {
          ctx.addIssue({
            code: z.ZodIssueCode.custom,
            message: "Please enter Professional Registration ID",
            path: ["professionalRegistrationId"],
          });
        }
      }).parse(req.body);

      // Check subscription limits based on role
      // Only block when remaining slots = 0, allow when remaining slots > 0
      const organizationId = req.tenant!.id;

      // Get active subscription for the organization using storage.getSubscription()
      // This method already filters by expiresAt (only returns subscriptions where expiresAt > current date)
      const subscription = await storage.getSubscription(organizationId);

      if (subscription) {
        // Extract maxUsers and maxPatients from subscription
        // subscription.userLimit comes from saasSubscriptions.maxUsers column
        // subscription.maxPatients comes from saasSubscriptions.maxPatients column (if selected)
        const packageFeatures = subscription.features as any || {};
        const maxUsers = subscription.userLimit || packageFeatures.maxUsers || 0;
        const maxPatients = (subscription as any).maxPatients || packageFeatures.maxPatients || 0;
        
        console.log('[POST /api/users] Subscription limits check:', {
          userLimit_from_subscription: subscription.userLimit,
          maxPatients_from_subscription: (subscription as any).maxPatients,
          maxUsers_from_features: packageFeatures.maxUsers,
          maxPatients_from_features: packageFeatures.maxPatients,
          final_maxUsers: maxUsers,
          final_maxPatients: maxPatients
        });

      // If creating a patient, check patient limits only
      if (userData.role === 'patient') {
          // Count existing patients (users with role='patient' and isActive=true)
        const [patientCount] = await db.select({
          count: sql<number>`count(*)::int`
        })
          .from(users)
          .where(
            and(
              eq(users.organizationId, organizationId),
                eq(users.role, 'patient'),
                eq(users.isActive, true)
            )
          );

        const currentPatientCount = patientCount?.count || 0;
          const remainingPatients = maxPatients - currentPatientCount;

          // Only block when remaining slots = 0 (allow when > 0)
          if (remainingPatients <= 0) {
          return res.status(403).json({
            error: `Patient limit reached. Your subscription allows ${maxPatients} patients, and you currently have ${currentPatientCount} patients. Please upgrade your subscription to add more patients.`
          });
        }
      } else {
        // For non-patient roles, check non-patient user limits
          // Exclude SaaS owners, inactive users, and patient role
        const [nonPatientUserCount] = await db.select({
          count: sql<number>`count(*)::int`
        })
          .from(users)
          .where(
            and(
              eq(users.organizationId, organizationId),
                ne(users.role, 'patient'),
                eq(users.isSaaSOwner, false),
                eq(users.isActive, true)
            )
          );

        const currentNonPatientUserCount = nonPatientUserCount?.count || 0;
          const remainingUsers = maxUsers - currentNonPatientUserCount;

          // Only block when remaining slots = 0 (allow when > 0)
          if (remainingUsers <= 0) {
          return res.status(403).json({
            error: `User limit reached. Your subscription allows ${maxUsers} users, and you currently have ${currentNonPatientUserCount} users. Please upgrade your subscription to add more users.`
          });
        }
      }
      }
      // If no subscription found, allow creation (don't block)

      if (userData.role === "patient" && !isPatientEncryptionConfigured()) {
        return res.status(503).json({
          error:
            "Patient encryption is not configured. Ensure the encryption SDK is installed and vault metadata is present, then restart the application.",
        });
      }

      // Hash password
      const hashedPassword = await authService.hashPassword(userData.password);

      // Generate default permissions based on role
      const defaultPermissions = getDefaultPermissionsByRole(userData.role);

      const { password, ...userDataWithoutPassword } = userData;
      const user = await storage.createUser({
        ...userDataWithoutPassword,
        organizationId: req.tenant!.id,
        passwordHash: hashedPassword,
        permissions: defaultPermissions
      });

      console.log(`Created user with role: ${userData.role} and permissions:`, defaultPermissions);

      // If user role is patient, automatically create encrypted patient record (encryption-sdk + vault metadata)
      let createdPatientRecord: Awaited<ReturnType<typeof storage.createPatient>> | undefined;
      if (userData.role === "patient") {
        console.log("Creating encrypted patient record for user with role 'patient'");

        try {
          const patientCount = await storage.countPatientsInOrganization(req.tenant!.id);
          const patientId = `P${(patientCount + 1).toString().padStart(6, "0")}`;

          const patientAddress = normalizePatientAddressForStorage(userData.address);
          const patientPhone = String(userData.phone ?? "").trim();
          const patientEmail = String(userData.email).trim();
          const patientNhs = String(userData.nhsNumber ?? "").trim();
          const patientGender = String(userData.genderAtBirth ?? "").trim();

          createdPatientRecord = await storage.createPatient({
            organizationId: req.tenant!.id,
            userId: user.id,
            patientId,
            firstName: userData.firstName,
            lastName: userData.lastName,
            relation: "Self",
            email: patientEmail,
            phone: patientPhone,
            nhsNumber: patientNhs || undefined,
            dateOfBirth: userData.dateOfBirth || "1990-01-01",
            genderAtBirth: patientGender || undefined,
            address: patientAddress,
            emergencyContact: userData.emergencyContact || {},
            insuranceInfo: userData.insuranceInfo || {},
            medicalHistory: {
              allergies: [],
              chronicConditions: [],
              medications: [],
              familyHistory: {
                father: [],
                mother: [],
                siblings: [],
                grandparents: [],
              },
              socialHistory: {
                smoking: { status: "never" as const },
                alcohol: { status: "never" as const },
                drugs: { status: "never" as const },
                occupation: "",
                maritalStatus: "single" as const,
                education: "",
                exercise: { frequency: "none" as const },
              },
              immunizations: [],
            },
            riskLevel: "low",
            isActive: true,
            isInsured: Boolean(userData.insuranceInfo?.provider),
            createdBy: req.user?.id,
          });

          console.log(
            `Created encrypted patient record with ID: ${createdPatientRecord.id}, patientId: ${createdPatientRecord.patientId}, userId: ${createdPatientRecord.userId}`,
          );

          const insurance = userData.insuranceInfo;
          if (
            insurance &&
            (insurance.provider?.trim() || insurance.policyNumber?.trim())
          ) {
            await storage.createInsuranceVerification({
              organizationId: req.tenant!.id,
              patientId: createdPatientRecord.id,
              patientName: `${userData.firstName} ${userData.lastName}`,
              provider: insurance.provider || "",
              policyNumber: insurance.policyNumber || "",
              groupNumber: insurance.groupNumber || null,
              memberNumber: insurance.memberNumber || null,
              nhsNumber: userData.nhsNumber || null,
              planType: insurance.planType || null,
              coverageType: "primary",
              status: "active",
              eligibilityStatus: "pending",
              effectiveDate: insurance.effectiveDate
                ? new Date(insurance.effectiveDate)
                : null,
              expirationDate: null,
              lastVerified: null,
              benefits: {},
            });
            console.log(
              `Created insurance_verifications row for patient id=${createdPatientRecord.id}`,
            );
          }
        } catch (patientError) {
          console.error("Encrypted patient record creation failed; rolling back user:", patientError);
          await storage.deleteUser(user.id, req.tenant!.id);
          throw patientError;
        }
      }

      // Remove password from response
      const { passwordHash, ...safeUser } = user;
      res.status(201).json(
        createdPatientRecord
          ? { ...safeUser, patient: createdPatientRecord }
          : safeUser,
      );
    } catch (error: any) {
      console.error("User creation error:", error);
      if (error instanceof z.ZodError) {
        return res.status(400).json({
          error: "Validation failed",
          details: error.errors.map(e => `${e.path.join('.')}: ${e.message}`)
        });
      }

      // Handle duplicate username error
      if (error.code === '23505' && error.constraint === 'users_username_key') {
        return res.status(400).json({
          error: "Username already exists. Please choose a different username."
        });
      }

      // Handle duplicate email error
      if (error.code === '23505' && error.constraint === 'users_email_key') {
        return res.status(400).json({
          error: "Email address already exists. Please use a different email."
        });
      }

      const errorMessage = error instanceof Error ? error.message : String(error);
      if (
        error?.code === "SDK_NOT_CONFIGURED" ||
        errorMessage.includes("Encryption SDK is not configured")
      ) {
        return res.status(503).json({
          error:
            "Patient encryption is not configured. Ensure the encryption SDK is installed with vault metadata, then restart the application.",
        });
      }

      if (
        error?.code === "BACKEND_DATAKEY_FAILED" ||
        error?.code === "BACKEND_DECRYPT_FAILED" ||
        error?.code === "LOCAL_DEK_UNAVAILABLE" ||
        /Backend datakey|Backend DEK|BACKEND_DATAKEY|LOCAL_DEK_UNAVAILABLE/i.test(
          errorMessage,
        )
      ) {
        const vaultHint =
          error?.code === "LOCAL_DEK_UNAVAILABLE"
            ? "Set FILE_SECRET or ENCRYPTION_KEY in the environment for local DEK fallback when the vault is down."
            : "Check VAULT_API_ENDPOINT (or encryption-sdk/.sdk-metadata) and that the Inkrypt vault is reachable.";
        return res.status(503).json({
          error: `Could not encrypt patient data. ${vaultHint}`,
          details: errorMessage.slice(0, 500),
        });
      }

      res.status(500).json({
        error: "Failed to create user",
        ...(errorMessage ? { details: errorMessage.slice(0, 500) } : {}),
      });
    }
  });

