  // Public: submit patient self-registration form
  app.post("/api/public/:subdomain/patient-self-register", async (req: TenantRequest, res) => {
    try {
      const subdomain = String(req.params.subdomain || "").trim();
      if (!subdomain) return res.status(400).json({ error: "Invalid subdomain" });

      const insuranceInfoSchema = z
        .object({
          provider: z.string().optional(),
          planType: z.string().optional(),
          policyNumber: z.string().optional(),
          memberNumber: z.string().optional(),
          groupNumber: z.string().optional(),
          effectiveDate: z.string().optional(),
          expirationDate: z.string().optional(),
        })
        .optional()
        .default({});

      const dependentChildSchema = z
        .object({
          firstName: z.string().optional().default(""),
          lastName: z.string().optional().default(""),
          dateOfBirth: z.string().optional().default(""),
          genderAtBirth: z.string().optional().default(""),
          nhsNumber: z.string().optional().default(""),
          phone: z.string().optional().default(""),
        })
        .optional()
        .default({});

      const body = z
        .object({
          token: z.string().min(5),
          firstName: z.string().min(1),
          lastName: z.string().min(1),
          email: z.string().email(),
          phone: z.string().min(1, "Phone is required"),
          dateOfBirth: z.string().min(1, "Date of birth is required"),
          genderAtBirth: z.string().min(1, "Gender at birth is required"),
          nhsNumber: z.string().optional().default(""),
          address: z
            .object({
              street: z.string().optional(),
              city: z.string().optional(),
              state: z.string().optional(),
              postcode: z.string().optional(),
              country: z.string().optional(),
              building: z.string().optional(),
            })
            .optional()
            .default({}),
          emergencyContact: z.object({
            name: z.string().min(1, "Emergency contact name is required"),
            relationship: z.string().min(1, "Relationship is required"),
            phone: z.string().min(1, "Emergency contact phone is required"),
            email: z.string().optional().default(""),
          }),
          insuranceInfo: insuranceInfoSchema,
          department: z.string().optional().default(""),
          password: z.string().optional().default(""),
          confirmPassword: z.string().optional().default(""),
          includeDependentChild: z.preprocess(
            (v) => v === true || v === "true",
            z.boolean().optional().default(false),
          ),
          dependentChild: dependentChildSchema,
          consentAccepted: z.preprocess(
            (val) => val === true || val === "true",
            z.boolean().refine((v) => v === true, { message: "You must accept the terms to register" }),
          ),
        })
        .superRefine((data, ctx) => {
          const selfDob = parseIsoDateOnlyUTC(data.dateOfBirth);
          if (!selfDob) {
            ctx.addIssue({
              code: z.ZodIssueCode.custom,
              message: "Enter a valid date of birth",
              path: ["dateOfBirth"],
            });
          } else {
            const today = startOfTodayUtcDate();
            if (selfDob.getTime() > today.getTime()) {
              ctx.addIssue({
                code: z.ZodIssueCode.custom,
                message: "Date of birth cannot be in the future",
                path: ["dateOfBirth"],
              });
            }
            const selfAge = ageYearsFromDobUTC(selfDob);
            if (selfAge > 130) {
              ctx.addIssue({
                code: z.ZodIssueCode.custom,
                message: "Please check the date of birth",
                path: ["dateOfBirth"],
              });
            }
          }

          const ecEmail = String(data.emergencyContact?.email || "").trim();
          if (ecEmail && !z.string().email().safeParse(ecEmail).success) {
            ctx.addIssue({
              code: z.ZodIssueCode.custom,
              message: "Enter a valid emergency contact email or leave it blank",
              path: ["emergencyContact", "email"],
            });
          }

          const ins = data.insuranceInfo || {};
          const eff = String(ins.effectiveDate || "").trim();
          if (eff && !parseIsoDateOnlyUTC(eff)) {
            ctx.addIssue({
              code: z.ZodIssueCode.custom,
              message: "Enter a valid insurance effective date",
              path: ["insuranceInfo", "effectiveDate"],
            });
          }
          const exp = String(ins.expirationDate || "").trim();
          if (exp && !parseIsoDateOnlyUTC(exp)) {
            ctx.addIssue({
              code: z.ZodIssueCode.custom,
              message: "Enter a valid insurance end date",
              path: ["insuranceInfo", "expirationDate"],
            });
          }

          const nhs = String(data.nhsNumber || "").replace(/\s/g, "");
          if (nhs && !/^\d{10}$/.test(nhs)) {
            ctx.addIssue({
              code: z.ZodIssueCode.custom,
              message: "NHS number must be 10 digits",
              path: ["nhsNumber"],
            });
          }

          if (!data.includeDependentChild) return;
          const d = data.dependentChild || {};
          if (!String(d.firstName || "").trim()) {
            ctx.addIssue({ code: z.ZodIssueCode.custom, message: "Dependent first name is required", path: ["dependentChild", "firstName"] });
          }
          if (!String(d.lastName || "").trim()) {
            ctx.addIssue({ code: z.ZodIssueCode.custom, message: "Dependent last name is required", path: ["dependentChild", "lastName"] });
          }
          if (!String(d.dateOfBirth || "").trim()) {
            ctx.addIssue({ code: z.ZodIssueCode.custom, message: "Dependent date of birth is required", path: ["dependentChild", "dateOfBirth"] });
          }
          if (!String(d.genderAtBirth || "").trim()) {
            ctx.addIssue({ code: z.ZodIssueCode.custom, message: "Dependent gender at birth is required", path: ["dependentChild", "genderAtBirth"] });
          }

          const depDobStr = String(d.dateOfBirth || "").trim();
          if (depDobStr) {
            const depDob = parseIsoDateOnlyUTC(depDobStr);
            if (!depDob) {
              ctx.addIssue({
                code: z.ZodIssueCode.custom,
                message: "Enter a valid dependent date of birth",
                path: ["dependentChild", "dateOfBirth"],
              });
            } else {
              const today = startOfTodayUtcDate();
              if (depDob.getTime() > today.getTime()) {
                ctx.addIssue({
                  code: z.ZodIssueCode.custom,
                  message: "Dependent date of birth cannot be in the future",
                  path: ["dependentChild", "dateOfBirth"],
                });
              }
              const depAge = ageYearsFromDobUTC(depDob);
              if (depAge >= 18) {
                ctx.addIssue({
                  code: z.ZodIssueCode.custom,
                  message: "Dependent must be under 18. Use a separate registration for adults.",
                  path: ["dependentChild", "dateOfBirth"],
                });
              }
            }
          }

          const depNhs = String(d.nhsNumber || "").replace(/\s/g, "");
          if (depNhs && !/^\d{10}$/.test(depNhs)) {
            ctx.addIssue({
              code: z.ZodIssueCode.custom,
              message: "Dependent NHS number must be 10 digits",
              path: ["dependentChild", "nhsNumber"],
            });
          }
        })
        .parse(req.body || {});

      await pool.query(`
        CREATE TABLE IF NOT EXISTS patient_registration_invites (
          id SERIAL PRIMARY KEY,
          organization_slug TEXT NOT NULL,
          email_to TEXT NOT NULL,
          token TEXT UNIQUE NOT NULL,
          portal_access BOOLEAN NOT NULL DEFAULT true,
          status TEXT NOT NULL DEFAULT 'sent',
          expires_at TIMESTAMPTZ,
          created_by_user_id INTEGER,
          created_at TIMESTAMPTZ DEFAULT now(),
          used_at TIMESTAMPTZ
        )
      `);

      // Resolve organization by subdomain (older DBs may not have a `slug` column)
      const orgRes = await pool.query(
        `SELECT id, name, subdomain FROM organizations WHERE subdomain = $1 LIMIT 1`,
        [subdomain],
      );
      if (orgRes.rows.length === 0) {
        return res.status(404).json({ error: "Organization not found" });
      }
      const organizationId = Number(orgRes.rows[0].id);

      // Validate token belongs to org + not expired/used
      const inviteRes = await pool.query(
        `SELECT id, email_to, portal_access, status, expires_at, used_at
         FROM patient_registration_invites
         WHERE organization_slug = $1 AND token = $2
         LIMIT 1`,
        [subdomain, body.token],
      );
      if (inviteRes.rows.length === 0) {
        return res.status(404).json({ error: "Token not found" });
      }
      const invite = inviteRes.rows[0];
      const expiresAt = invite.expires_at ? new Date(invite.expires_at) : null;
      if (expiresAt && expiresAt.getTime() < Date.now()) {
        return res.status(410).json({ error: "Token expired" });
      }
      if (String(invite.status || "").toLowerCase() === "used" || invite.used_at) {
        return res.status(409).json({ error: "Token already used" });
      }

      // Enforce invited email (locks the email field client-side too)
      const invitedEmail = String(invite.email_to || "").trim().toLowerCase();
      const submittedEmail = String(body.email || "").trim().toLowerCase();
      if (invitedEmail && invitedEmail !== submittedEmail) {
        return res.status(400).json({ error: "Email does not match invite" });
      }

      // Create (or reuse) User if portal access enabled
      let createdUser: any = null;
      let userId: number | null = null;
      const enablePortalAccess = !!invite.portal_access;

      let plainPassword: string | null = null;
      if (enablePortalAccess) {
        const existingUser = await storage.getUserByEmailGlobal(submittedEmail);
        if (existingUser) {
          if (existingUser.organizationId !== organizationId) {
            return res.status(409).json({
              error:
                "This email is already registered to another clinic account. Use the email from your invite or contact support.",
            });
          }
          if (String(existingUser.role || "").toLowerCase() !== "patient") {
            return res.status(409).json({
              error: "This email is already used by a staff account. Please use a different personal email for patient registration.",
            });
          }
          const existingForUser = await storage.getPatientsByUserId(organizationId, existingUser.id);
          if (existingForUser.some((p) => String(p.relation || "").trim().toLowerCase() === "self")) {
            return res.status(409).json({
              error: "A patient profile already exists for this account at this clinic. Sign in or ask reception for help.",
            });
          }
          userId = existingUser.id;
        } else {
          const pw = String(body.password || "").trim();
          const pwConfirm = String(body.confirmPassword || "").trim();
          let passwordHash: string;
          if (pw) {
            if (pw.length < 8) {
              return res.status(400).json({ error: "Password must be at least 8 characters" });
            }
            if (pw !== pwConfirm) {
              return res.status(400).json({ error: "Passwords do not match" });
            }
            passwordHash = await authService.hashPassword(pw);
            plainPassword = null;
          } else {
            plainPassword = `PT_${Math.random().toString(36).slice(2, 8)}${Math.random().toString(36).slice(2, 8)}`;
            passwordHash = await authService.hashPassword(plainPassword);
          }
          const defaultPermissions = getDefaultPermissionsByRole("patient");
          const dept = String(body.department || "").trim();
          createdUser = await storage.createUser({
            organizationId,
            email: submittedEmail,
            username: submittedEmail,
            firstName: body.firstName,
            lastName: body.lastName,
            role: "patient",
            isActive: true,
            phone: body.phone || "",
            dateOfBirth: body.dateOfBirth,
            genderAtBirth: body.genderAtBirth,
            ...(dept ? { department: dept } : {}),
            passwordHash,
            permissions: defaultPermissions,
          } as any);
          userId = createdUser.id;

          // Email credentials only when a temporary password was generated
          if (plainPassword) {
            try {
              const userName = `${body.firstName} ${body.lastName}`.trim();
              const credSent = await emailService.sendNewUserAccountEmail(
                submittedEmail,
                userName,
                plainPassword,
                String(orgRes.rows[0].name || "Clinic"),
                "patient",
              );
              if (!credSent) {
                console.error("[PUBLIC-SELF-REG] Portal credentials email failed (check server logs)");
              }
            } catch (mailErr) {
              console.error("[PUBLIC-SELF-REG] Welcome email failed:", mailErr);
            }
          }
        }
      }

      // Create patient record (always)
      const generatedPatientId = await allocateNextDisplayPatientId(organizationId);

      const insRaw = body.insuranceInfo || {};
      const isInsured = Boolean(
        String(insRaw.provider || "").trim() ||
          String(insRaw.policyNumber || "").trim() ||
          String(insRaw.memberNumber || "").trim() ||
          String(insRaw.planType || "").trim(),
      );

      const patient = await storage.createPatient({
        organizationId,
        userId: userId ?? undefined,
        patientId: generatedPatientId,
        firstName: body.firstName,
        lastName: body.lastName,
        relation: "Self",
        dateOfBirth: body.dateOfBirth ? body.dateOfBirth : undefined,
        genderAtBirth: body.genderAtBirth,
        email: submittedEmail,
        phone: body.phone || "",
        nhsNumber: String(body.nhsNumber || "").trim() || undefined,
        address: body.address || {},
        emergencyContact: {
          name: String(body.emergencyContact.name || "").trim(),
          relationship: String(body.emergencyContact.relationship || "").trim(),
          phone: String(body.emergencyContact.phone || "").trim(),
          email: String(body.emergencyContact.email || "").trim() || undefined,
        },
        insuranceInfo: {
          provider: String(insRaw.provider || "").trim() || undefined,
          planType: String(insRaw.planType || "").trim() || undefined,
          policyNumber: String(insRaw.policyNumber || "").trim() || undefined,
          memberNumber: String(insRaw.memberNumber || "").trim() || undefined,
          groupNumber: String(insRaw.groupNumber || "").trim() || undefined,
          effectiveDate: String(insRaw.effectiveDate || "").trim() || undefined,
          expirationDate: String(insRaw.expirationDate || "").trim() || undefined,
        },
        isInsured,
        createdBy: null as any,
      } as any);

      let dependentPatient: { id: number; patientId: string } | null = null;
      if (body.includeDependentChild && body.dependentChild) {
        const d = body.dependentChild;
        const generatedDependentPatientId = await allocateNextDisplayPatientId(organizationId);
        const dep = await storage.createPatient({
          organizationId,
          userId: userId ?? undefined,
          patientId: generatedDependentPatientId,
          firstName: String(d.firstName || "").trim(),
          lastName: String(d.lastName || "").trim(),
          relation: "Dependent Child",
          dateOfBirth: String(d.dateOfBirth || "").trim() || undefined,
          genderAtBirth: String(d.genderAtBirth || "").trim(),
          email: submittedEmail,
          phone: String(d.phone || "").trim() || "",
          nhsNumber: String(d.nhsNumber || "").trim() || undefined,
          address: body.address || {},
          emergencyContact: {
            name: String(body.emergencyContact.name || "").trim(),
            relationship: String(body.emergencyContact.relationship || "").trim(),
            phone: String(body.emergencyContact.phone || "").trim(),
            email: String(body.emergencyContact.email || "").trim() || undefined,
          },
          insuranceInfo: {},
          isInsured: false,
          createdBy: null as any,
        } as any);
        dependentPatient = { id: dep.id, patientId: dep.patientId };
      }

      await pool.query(
        `UPDATE patient_registration_invites
         SET status = 'used', used_at = now()
         WHERE id = $1`,
        [invite.id],
      );

      const organizationName = String(orgRes.rows[0].name || "Clinic");
      const patientDisplayName = `${body.firstName} ${body.lastName}`.trim();
      let confirmationEmailSent = false;
      let confirmationEmailError: string | undefined;
      try {
        const publicBase =
          process.env.PUBLIC_APP_URL ||
          process.env.APP_PUBLIC_URL ||
          process.env.APP_BASE_URL ||
          process.env.WEB_BASE_URL ||
          process.env.VITE_API_URL ||
          process.env.BASE_URL ||
          process.env.APP_URL ||
          "";
        const hostFallback = (() => {
          try {
            const proto = (req as any).protocol || "http";
            const host = req.get && req.get("host");
            return host ? `${proto}://${host}` : "";
          } catch {
            return "";
          }
        })();
        const baseUrl = (publicBase || hostFallback).replace(/\/$/, "");
        const loginPath = `/${encodeURIComponent(subdomain)}/auth/login`;
        const loginUrl = baseUrl ? `${baseUrl}${loginPath}` : "";
        const mailReport = await emailService.sendPatientRegistrationSuccessEmail(
          submittedEmail,
          patientDisplayName,
          organizationName,
          patient.patientId,
          { portalAccess: enablePortalAccess, loginUrl },
        );
        confirmationEmailSent = mailReport.success;
        if (!mailReport.success) {
          confirmationEmailError = mailReport.error;
          console.error(
            "[PUBLIC-SELF-REG] Registration confirmation email not sent:",
            mailReport.error,
          );
        }
      } catch (mailErr) {
        confirmationEmailError =
          mailErr instanceof Error ? mailErr.message : String(mailErr);
        console.error("[PUBLIC-SELF-REG] Registration confirmation email failed:", mailErr);
      }

      return res.json({
        success: true,
        portalAccess: enablePortalAccess,
        patient: { id: patient.id, patientId: patient.patientId },
        dependentPatient,
        user: userId ? { id: userId, email: submittedEmail } : null,
        confirmationEmailSent,
        ...(process.env.NODE_ENV !== "production" && confirmationEmailError
          ? { confirmationEmailError }
          : {}),
      });
    } catch (error) {
      console.error("[PUBLIC-SELF-REG] Error:", error);
      if (error instanceof z.ZodError) {
        return res.status(400).json({ error: "Validation failed", details: error.errors });
      }
      const errAny = error as { code?: string; cause?: { code?: string } };
      const errCode = errAny?.code || errAny?.cause?.code;
      if (errCode === "23505") {
        return res.status(409).json({
          error:
            "This registration conflicts with an existing record. If you already registered, sign in or request a new link from the clinic.",
        });
      }
      const msg = error instanceof Error ? error.message : String(error);
      if (process.env.NODE_ENV !== "production") {
        return res.status(500).json({ error: "Registration failed", details: msg });
      }
      return res.status(500).json({ error: "Registration failed" });
    }
  });
  // Share lab result PDF via email to patient
  app.post("/api/lab-results/:id/share-email", authMiddleware, requireNonPatientRole(), async (req: TenantRequest, res) => {
    try {
      if (!req.user) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      const labResultId = parseInt(req.params.id);
      if (isNaN(labResultId)) {
        return res.status(400).json({ error: "Invalid lab result ID" });
      }

      // Use the user's org for file + data lookup (more reliable than req.tenant in some auth flows).
      const organizationId = (req.user as any)?.organizationId ?? req.tenant?.id;
      if (!organizationId) {
        return res.status(400).json({ error: "Organization ID is required" });
      }

      const labResults = await storage.getLabResults(organizationId);
      const labResult = labResults.find(r => r.id === labResultId);
      if (!labResult) {
        return res.status(404).json({ error: "Lab result not found" });
      }

      const patient = await storage.getPatient(labResult.patientId, organizationId);
      if (!patient) {
        return res.status(404).json({ error: "Patient not found" });
      }

      // Allow caller to override the recipient email (e.g. from the share dialog)
      const recipientEmail: string = (req.body?.recipientEmail || patient.email || "").trim();
      if (!recipientEmail) {
        return res.status(422).json({ error: "No recipient email address available. Please enter an email in the share dialog or add one to the patient record." });
      }

      const customMessage: string = (req.body?.message || "").trim();

      const pdfDirectoryName = 'Lab_TestResults';
      const fileName = `${labResult.testId}.pdf`;
      const filePath = path.join(process.cwd(), 'uploads', pdfDirectoryName, organizationId.toString(), labResult.patientId.toString(), fileName);

      const fileExists = await fse.pathExists(filePath);
      if (!fileExists) {
        return res.status(404).json({ error: "PDF not found. Please generate the report first." });
      }

      const fsModule = await import('fs');
      const fileBuffer = fsModule.readFileSync(filePath);

      const patientName = `${patient.firstName} ${patient.lastName}`.trim();
      const sharedBy = `${req.user.firstName ?? ""} ${req.user.lastName ?? ""}`.trim() || req.user.email || "emrSoft";
      const customPart = customMessage ? `<p>${customMessage}</p>` : "";
      const customTextPart = customMessage ? `${customMessage}\n\n` : "";

      const result = await emailService.sendEmailWithReport({
        to: recipientEmail,
        subject: `Your Lab Test Result — ${labResult.testId}`,
        html: `<p>Dear ${patientName},</p>${customPart}<p>Please find your lab test result attached (Test ID: <strong>${labResult.testId}</strong>).</p><p>Shared by: ${sharedBy}</p><p>If you have any questions, please contact your healthcare provider.</p><p>Regards,<br/>emrSoft Team</p>`,
        text: `Dear ${patientName},\n\n${customTextPart}Please find your lab test result attached (Test ID: ${labResult.testId}).\n\nShared by: ${sharedBy}\n\nIf you have any questions, please contact your healthcare provider.\n\nRegards,\nemrSoft Team`,
        attachments: [{
          filename: fileName,
          content: fileBuffer,
          contentType: 'application/pdf',
        }],
      });

      if (!result.success) {
        const errMsg = result.error || "Failed to send email";
        const isConfigError = errMsg.includes("credentials") || errMsg.includes("SENDGRID_API_KEY") || errMsg.includes("not set") || errMsg.includes("not configured") || errMsg.includes("ENOTFOUND") || errMsg.includes("ECONNREFUSED");
        if (isConfigError) {
          return res.status(503).json({ error: "Email delivery is not configured for this system. Please contact your administrator." });
        }
        return res.status(500).json({ error: "Failed to send email.", details: errMsg });
      }

      console.log(`[LAB-SHARE] Emailed ${fileName} to ${recipientEmail} for lab result ${labResultId}`);
      return res.json({ success: true, email: recipientEmail, patientName });
    } catch (error) {
      console.error("Error sharing lab result via email:", error);
      res.status(500).json({
        error: "Failed to share lab result",
        details: error instanceof Error ? error.message : String(error),
      });
    }
  });

  // Delete lab result PDF (prescription or test result)
  app.delete("/api/lab-results/:id/delete-pdf", authMiddleware, requireNonPatientRole(), async (req: TenantRequest, res) => {
    try {
      if (!req.user) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      const labResultId = parseInt(req.params.id);
      if (isNaN(labResultId)) {
        return res.status(400).json({ error: "Invalid lab result ID" });
      }

      const organizationId = req.tenant!.id;

      // Check if this is a prescription PDF request
      const isPrescription = req.query.type === 'prescription';

      // Fetch lab result
      const labResults = await storage.getLabResults(organizationId);
      const labResult = labResults.find(result => result.id === labResultId);

      if (!labResult) {
        return res.status(404).json({ error: "Lab result not found" });
      }

      // Construct file path based on type
      const pdfDirectoryName = isPrescription ? 'Lab_Prescription' : 'Lab_TestResults';
      const fileName = `${labResult.testId}.pdf`;
      const filePath = path.join(process.cwd(), 'uploads', pdfDirectoryName, organizationId.toString(), labResult.patientId.toString(), fileName);

      console.log(`[LAB-DELETE] Lab result ID: ${labResultId}`);
      console.log(`[LAB-DELETE] Organization ID: ${organizationId}`);
      console.log(`[LAB-DELETE] Type: ${isPrescription ? 'prescription' : 'test result'}`);
      console.log(`[LAB-DELETE] File path: ${filePath}`);

      // Check if file exists
      const fileExists = await fse.pathExists(filePath);
      console.log(`[LAB-DELETE] File exists: ${fileExists}`);

      if (!fileExists) {
        return res.status(404).json({ error: "PDF file not found." });
      }

      // Delete the file
      await fse.remove(filePath);
      console.log(`[LAB-DELETE] File deleted successfully: ${filePath}`);

      // If prescription is deleted, optionally reset readyToGenerateLab flag
      if (isPrescription) {
        try {
          await storage.updateLabResult(labResultId, organizationId, {
            readyToGenerateLab: false
          });
          console.log(`[LAB-DELETE] Reset ready_to_generate_lab to false for lab result ID: ${labResultId}`);
        } catch (updateError) {
          console.error(`[LAB-DELETE] Error updating workflow fields:`, updateError);
          // Don't fail the request if update fails
        }
      }

      res.json({
        success: true,
        message: "PDF deleted successfully"
      });

    } catch (error) {
      console.error("Error deleting lab result PDF:", error);
      res.status(500).json({ error: "Failed to delete PDF" });
    }
  });

  // Migrate lab results to add testType field to each result object
  app.post("/api/lab-results/migrate-test-types", authMiddleware, requireNonPatientRole(), async (req: TenantRequest, res) => {
    try {
      if (!req.user) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      const organizationId = req.tenant!.id;
      const labResultsList = await storage.getLabResults(organizationId);

      let updatedCount = 0;
      let alreadyMigratedCount = 0;

      for (const labResult of labResultsList) {
        if (!labResult.results || !labResult.testType) continue;

        const results = typeof labResult.results === 'string'
          ? JSON.parse(labResult.results)
          : labResult.results;

        if (!Array.isArray(results) || results.length === 0) continue;

        // Check if already migrated (first result has testType field)
        if (results[0]?.testType) {
          alreadyMigratedCount++;
          continue;
        }

        // Parse test types from testType field
        const testTypesStr = labResult.testType;
        let testTypes: string[] = [];
        try {
          const parsed = JSON.parse(testTypesStr);
          testTypes = Array.isArray(parsed) ? parsed : [testTypesStr];
        } catch {
          testTypes = testTypesStr.split('|').map(t => t.trim()).filter(t => t.length > 0);
        }

        // Build a map of parameter names to test types
        const TEST_FIELD_DEFINITIONS: Record<string, Array<{ name: string }>> = {
          "Complete Blood Count (CBC)": [
            { name: "White Blood Cell Count (WBC)" },
            { name: "Red Blood Cell Count (RBC)" },
            { name: "Hemoglobin (Hb)" },
            { name: "Hematocrit (Hct)" },
            { name: "Mean Corpuscular Volume (MCV)" },
            { name: "Mean Corpuscular Hemoglobin (MCH)" },
            { name: "Mean Corpuscular Hemoglobin Concentration (MCHC)" },
            { name: "Platelet Count" },
            { name: "Red Cell Distribution Width (RDW)" },
          ],
          "Hormonal tests (Cortisol, ACTH)": [
            { name: "Cortisol (AM)" },
            { name: "Cortisol (PM)" },
            { name: "ACTH (Adrenocorticotropic Hormone)" },
            { name: "24-hour Urinary Free Cortisol" },
          ],
          "Viral Panels / PCR Tests (e.g. COVID-19, Influenza)": [
            { name: "COVID-19 PCR" },
            { name: "Influenza A PCR" },
            { name: "Influenza B PCR" },
            { name: "RSV PCR" },
          ],
          "Bacterial Culture/Sensitivity Testing": [
            { name: "Culture Result" },
            { name: "Gram Stain" },
            { name: "AFB (Acid-Fast Bacilli)" },
            { name: "Fungal Culture" },
          ],
        };

        // Create parameter name to testType mapping
        const paramToTestType: Record<string, string> = {};
        testTypes.forEach(testType => {
          const fields = TEST_FIELD_DEFINITIONS[testType];
          if (fields) {
            fields.forEach(field => {
              paramToTestType[field.name] = testType;
            });
          }
        });

        // Update results array with testType field
        const updatedResults = results.map((result: any) => {
          const paramName = result.testName || result.name || '';
          const testType = paramToTestType[paramName] || testTypes[0];
          return {
            ...result,
            testType
          };
        });

        // Update lab result in database
        await storage.updateLabResult(labResult.id!, organizationId, {
          results: JSON.stringify(updatedResults)
        });

        updatedCount++;
      }

      res.json({
        success: true,
        message: `Migration completed: ${updatedCount} lab results updated, ${alreadyMigratedCount} already migrated`,
        updatedCount,
        alreadyMigratedCount
      });

    } catch (error) {
      console.error("Error migrating lab results:", error);
      res.status(500).json({ error: "Failed to migrate lab results" });
    }
  });

  // Get Lab Result PDF Path
