  const formShareClientError = (err: unknown): string => {
    const raw =
      err instanceof Error ? err.message : typeof err === "string" ? err : "Request failed";
    const htmlIdx = raw.search(/<!doctype|<html/i);
    const trimmed = (htmlIdx >= 0 ? raw.slice(0, htmlIdx) : raw).trim().replace(/:\s*$/, "");
    const message = trimmed || "Encryption service unavailable";
    return message.length > 400 ? `${message.slice(0, 397)}...` : message;
  };

  const isFormShareEncryptionUnavailable = (message: string): boolean =>
    /SDK_NOT_CONFIGURED|encryption is not configured|BACKEND_DATAKEY|BACKEND_DECRYPT|Backend datakey|Backend DEK decrypt/i.test(
      message,
    );

  app.post(
    "/api/forms/:formId/share",
    authMiddleware,
    requireRole(["admin", "doctor", "nurse"]),
    async (req: TenantRequest, res) => {
      try {
        if (!req.user) {
          return res.status(401).json({ error: "User not authenticated" });
        }

        const organizationId = requireOrgId(req);
        const formId = Number(req.params.formId);
        const body =
          req.body && typeof req.body === "object" && !Array.isArray(req.body) ? req.body : {};
        const recipientEmail =
          typeof body.recipientEmail === "string"
            ? body.recipientEmail.trim()
            : typeof body.email === "string"
              ? body.email.trim()
              : "";
        if (!Number.isFinite(formId) || formId <= 0) {
          return res.status(400).json({ error: "Valid formId is required" });
        }
        if (!recipientEmail) {
          return res.status(400).json({ error: "recipientEmail is required" });
        }
        if (!recipientEmail.includes("@")) {
          return res.status(400).json({ error: "recipientEmail must be a valid email address" });
        }

        let resolvedPatient: { patientId: null; recipientEmail: string };
        try {
          resolvedPatient = await formService.resolvePatientForFormShare(
            organizationId,
            recipientEmail,
          );
        } catch (resolveError: unknown) {
          const message = formShareClientError(resolveError);
          return res.status(400).json({ error: message });
        }

        const sharePayload = {
          formId,
          organizationId,
          patientId: null as null,
          sentById: req.user.id,
          recipientEmail: resolvedPatient.recipientEmail,
        };

        const runShare = () => formService.shareForm(sharePayload);

        const isForeignKeyViolation = (err: unknown): boolean => {
          const e = err as { code?: string; message?: string };
          if (e?.code === "23503") return true;
          const m = e?.message ?? String(err);
          return /foreign key constraint/i.test(m);
        };

        try {
          const result = await runShare();
          return res.status(201).json(result);
        } catch (shareError: unknown) {
          if (!isForeignKeyViolation(shareError)) {
            throw shareError;
          }

          console.warn(
            "[FORMS] FK violation on form share — repointing form foreign keys and retrying once",
            shareError,
          );
          await fixFormForeignKeysForActiveSchema(pool, activeDbSchema);
          await repointFormSharePatientForeignKeys(pool, activeDbSchema);
          const result = await runShare();
          return res.status(201).json(result);
        }
      } catch (error) {
        console.error("Error sharing form:", error);
        const rawMessage = (error as Error).message || "Failed to share form";
        const message = formShareClientError(error);
        const code = (error as { code?: string }).code;

        if (isFormShareEncryptionUnavailable(rawMessage) || isFormShareEncryptionUnavailable(message)) {
          return res.status(503).json({
            error:
              "Patient encryption vault is unavailable. Sharing by recipient email should work without decrypting patient records; restart the API server. If this persists, verify VAULT_API_ENDPOINT.",
            detail: process.env.NODE_ENV === "development" ? message : undefined,
          });
        }

        if (
          message.includes("SDK_NOT_CONFIGURED") ||
          message.includes("Encryption SDK is not configured")
        ) {
          return res.status(503).json({
            error:
              "Patient encryption is not configured on this server. Ensure the encryption SDK is installed with vault metadata, then restart the API.",
            detail: process.env.NODE_ENV === "development" ? message : undefined,
          });
        }

        if (
          message.includes("INVALID_TAG") ||
          message.includes("Authentication failed") ||
          message.includes("DECRYPTION_FAILED")
        ) {
          return res.status(503).json({
            error:
              "Could not decrypt patient data for this share. The patient record may be corrupted or was encrypted with an unsupported format.",
            detail: process.env.NODE_ENV === "development" ? message.slice(0, 500) : undefined,
          });
        }

        if (
          code === "23503" ||
          (message.includes("foreign key constraint") &&
            (message.includes("patient_id") || message.includes("form_shares") || message.includes("form_share_logs")))
        ) {
          return res.status(400).json({
            error:
              "Could not link this patient to the form share. The database may still reference patients/forms in the wrong schema. Restart the app server (runs a one-time FK repair), then try again. If it persists, contact support.",
            detail:
              process.env.NODE_ENV === "development"
                ? message.slice(0, 500)
                : undefined,
          });
        }

        if (code === "42501" || /permission denied/i.test(message)) {
          return res.status(503).json({
            error:
              "Database user cannot update form-share constraints. Ask your DBA to run form FK repair on the tenant schema, or grant ALTER privileges to the app DB user.",
            detail: process.env.NODE_ENV === "development" ? message.slice(0, 500) : undefined,
          });
        }

        if (code === "42P01" || /relation .* does not exist/i.test(message)) {
          return res.status(503).json({
            error:
              "Form sharing tables are missing in the active database schema. Run migrations / ensure-db-schema on production, then restart the server.",
            detail: process.env.NODE_ENV === "development" ? message.slice(0, 500) : undefined,
          });
        }

        res.status(500).json({
          error: message,
          detail: process.env.NODE_ENV === "development" ? message.slice(0, 500) : undefined,
        });
      }
    },
  );

