  app.delete("/api/anatomical-analysis/files/:patientId", authMiddleware, async (req: TenantRequest, res) => {
    try {
      if (!req.user) {
        return res.status(401).json({ error: "User not authenticated" });
      }

      const patientId = parseInt(req.params.patientId);
      if (isNaN(patientId)) {
        return res.status(400).json({ error: "Invalid patient ID" });
      }

      const payload = z
        .object({
          filename: z.string(),
        })
        .parse(req.body);

      const organizationId = req.tenant!.id;
      const candidateDirs = [
        path.join(
          "./uploads",
          "anatomical_analysis_files",
          organizationId.toString(),
          "patients",
          patientId.toString(),
          "forms",
        ),
        path.join("./uploads", "anatomical_analysis_img", organizationId.toString(), patientId.toString()),
      ];

      let deleted = false;
      for (const baseDir of candidateDirs) {
        const targetPath = path.join(baseDir, payload.filename);

        if (!targetPath.startsWith(baseDir)) {
          continue;
        }

        const fileExists = await fs.promises
          .access(targetPath)
          .then(() => true)
          .catch(() => false);

        if (!fileExists) {
          continue;
        }

        await fs.promises.unlink(targetPath);
        deleted = true;
        break;
      }

      if (!deleted) {
        return res.status(404).json({ error: "File not found" });
      }

      res.json({ message: "File deleted successfully", filename: payload.filename });
    } catch (error) {
      console.error("Error deleting anatomical file:", error);
      handleRouteError(error, "delete anatomical file", res);
    }
  });

