  // Stripe Checkout Session for Subscription Upgrade
  app.post("/api/stripe/create-checkout-session", authMiddleware, async (req: TenantRequest, res) => {
    try {
      if (!stripe) {
        return res.status(500).json({ error: "Stripe is not configured" });
      }

      if (!req.user) {
        return res.status(401).json({ error: "Authentication required" });
      }

      const organizationId = req.organizationId;
      if (!organizationId) {
        return res.status(400).json({ error: "Organization context missing" });
      }

      const planId = Number(req.body.planId);
      if (Number.isNaN(planId)) {
        return res.status(400).json({ error: "Invalid plan ID" });
      }

      const pkg = await storage.getPackageById(planId);
      if (!pkg) {
        return res.status(404).json({ error: "Subscription package not found" });
      }

      // Get billing cycle from request or default to monthly
      const billingCycle = (req.body.billingCycle as "monthly" | "annual") || "monthly";
      
      // Get Stripe price ID from database - use getStripePriceId helper to get the correct price for billing cycle
      let priceId: string | null = null;
      
      if (req.body.stripePriceId) {
        // If explicitly provided, use it
        priceId = req.body.stripePriceId as string;
      } else {
        // Get price ID from database based on package and billing cycle
        try {
          const { getStripePriceId } = await import("./services/stripe-subscription");
          priceId = await getStripePriceId(planId, billingCycle);
        } catch (error: any) {
          console.error("Error getting Stripe price ID:", error);
          // Fallback to package's default stripePriceId
          priceId = pkg.stripePriceId;
        }
      }
      
      if (!priceId) {
        return res.status(400).json({ 
          error: "Stripe price ID is missing for this package. Please configure Stripe prices for this package in the database." 
        });
      }

      const userRecord = await storage.getUser(req.user.id, req.user.organizationId);
      if (!userRecord) {
        return res.status(404).json({ error: "User record missing" });
      }

      const customerId = await ensureStripeCustomer(stripe, userRecord, organizationId);

      const protocol = req.headers["x-forwarded-proto"] || "https";
      const host = req.headers.host;
      const baseUrl = `${protocol}://${host}`;
      const subdomain = (req.headers["x-tenant-subdomain"] as string) || "demo";
      const subscriptionPath = `/${subdomain}/subscription`;

      const session = await stripe.checkout.sessions.create({
        mode: "subscription",
        customer: customerId,
        line_items: [
          {
            price: priceId,
            quantity: 1,
          },
        ],
        payment_method_types: ["card"],
        success_url: `${baseUrl}${subscriptionPath}?success=true&session_id={CHECKOUT_SESSION_ID}`,
        cancel_url: `${baseUrl}${subscriptionPath}?canceled=true`,
        metadata: {
          packageId: pkg.id.toString(),
          organizationId: organizationId.toString(),
          userId: req.user.id.toString(),
          billingCycle: billingCycle,
          isUpgrade: req.body.isUpgrade ? "true" : "false",
          existingSubscriptionId: req.body.existingSubscriptionId?.toString() || "",
        },
      });

      console.log("[STRIPE CHECKOUT] Session created", { sessionId: session.id });

      res.json({ url: session.url, sessionId: session.id });
    } catch (error: any) {
      console.error("Error creating Stripe checkout session:", error);
      res.status(500).json({ error: error.message || "Failed to create checkout session" });
    }
  });

  app.get("/api/stripe/checkout-session/:sessionId", authMiddleware, async (req: TenantRequest, res) => {
    try {
      if (!stripe) {
        return res.status(500).json({ error: "Stripe is not configured" });
      }

      const sessionId = req.params.sessionId;
      if (!sessionId) {
        return res.status(400).json({ error: "Session ID is required" });
      }

      const session = await stripe.checkout.sessions.retrieve(sessionId, {
        expand: ["subscription", "invoice"],
      });

      if (!session) {
        return res.status(404).json({ error: "Checkout session not found" });
      }

      const sessionOrgId = session.metadata?.organizationId ? Number(session.metadata.organizationId) : null;
      if (!req.organizationId || !sessionOrgId || sessionOrgId !== req.organizationId) {
        return res.status(403).json({ error: "Session does not belong to your organization" });
      }

      // Sync subscription to database when user returns from Stripe (in case webhook hasn't run yet)
      const packageId = Number(session.metadata?.packageId || session.metadata?.planId);
      const organizationId = sessionOrgId;
      if (session.subscription && packageId && organizationId) {
        try {
          const stripeSubscription = typeof session.subscription === "string"
            ? await stripe.subscriptions.retrieve(session.subscription)
            : session.subscription;
          if (stripeSubscription && stripeSubscription.id) {
            await upsertSubscriptionFromStripe(stripeSubscription, organizationId, packageId);
          }
        } catch (syncErr: any) {
          console.error("[STRIPE CHECKOUT] Failed to sync subscription from session:", syncErr?.message);
        }
      }

      res.json(session);
    } catch (error: any) {
      console.error("Error retrieving Stripe checkout session:", error);
      res.status(500).json({ error: error.message || "Failed to fetch checkout session" });
    }
  });

  const STRIPE_WEBHOOK_SECRET = process.env.STRIPE_WEBHOOK_SECRET || process.env.STRIPE_WEBHOOK_SECRET_ENV || '';

  async function ensureStripeCustomer(
    stripeClient: Stripe,
    user: User,
    organizationId: number,
  ): Promise<string> {
    if (user.stripeCustomerId) {
      try {
        const existing = await stripeClient.customers.retrieve(user.stripeCustomerId);
        if (existing && !existing.deleted) {
          return existing.id;
        }
      } catch (err: any) {
        // No such customer, or customer deleted in Stripe — create a new one
        if (err?.code !== "resource_missing" && !/no such customer/i.test(err?.message || "")) {
          throw err;
        }
      }
      // Fall through to create new customer and update user
    }

    const customer = await stripeClient.customers.create({
      email: user.email,
      metadata: {
        organizationId: organizationId.toString(),
        userId: user.id.toString(),
      },
    });

    await storage.updateUser(user.id, organizationId, {
      stripeCustomerId: customer.id,
    });

    return customer.id;
  }

  async function upsertSubscriptionFromStripe(
    stripeSubscription: Stripe.Subscription,
    organizationId: number,
    packageId: number,
  ): Promise<any> {
    if (!organizationId || !packageId) {
      throw new Error("Missing context to persist Stripe subscription");
    }

    // Convert Stripe timestamps (already UTC) directly to Date objects without timezone conversion
    // Stripe timestamps are Unix timestamps in UTC, so multiply by 1000 to get milliseconds
    const currentPeriodStartUTC = stripeSubscription.current_period_start
      ? new Date(stripeSubscription.current_period_start * 1000)
      : new Date();
    const currentPeriodEndUTC = stripeSubscription.current_period_end
      ? new Date(stripeSubscription.current_period_end * 1000)
      : new Date();

    const payload: InsertSaaSSubscription = {
      organizationId,
      packageId,
      status: stripeSubscription.status,
      paymentStatus: ["active", "trialing"].includes(stripeSubscription.status) ? "paid" : "pending",
      currentPeriodStart: currentPeriodStartUTC,
      currentPeriodEnd: currentPeriodEndUTC,
      cancelAtPeriodEnd: Boolean(stripeSubscription.cancel_at_period_end),
      stripeSubscriptionId: stripeSubscription.id,
      metadata: {
        ...stripeSubscription.metadata,
        latestInvoiceId: stripeSubscription.latest_invoice?.toString(),
      },
    };

    const existing = await storage.getSaaSSubscriptionByStripeId(stripeSubscription.id);
    if (existing) {
      await storage.updateSaaSSubscription(existing.id, payload);
      // Ensure organization status is active
      await storage.updateOrganizationStatus(organizationId, "active");
      return existing;
    }

    const created = await storage.createSaaSSubscription(payload);
    await storage.updateOrganizationStatus(organizationId, "active");

    // After successfully creating subscription, if payment is successful, create payment and invoice records
    const isPaymentSuccessful = ["active", "trialing"].includes(stripeSubscription.status);
    if (isPaymentSuccessful && stripeSubscription.latest_invoice) {
      try {
        // Fetch the Stripe invoice
        const invoiceId = typeof stripeSubscription.latest_invoice === "string"
          ? stripeSubscription.latest_invoice
          : stripeSubscription.latest_invoice.id;
        
        if (invoiceId && stripe) {
          const stripeInvoice = await stripe.invoices.retrieve(invoiceId, {
            expand: ['lines']
          });

          if (stripeInvoice && stripeInvoice.status === 'paid') {
            // Convert Stripe invoice timestamps (already UTC) directly to Date objects without timezone conversion
            // Stripe timestamps are Unix timestamps in UTC, so multiply by 1000 to get milliseconds
            const periodStart = stripeInvoice.period_start
              ? new Date(stripeInvoice.period_start * 1000)
              : currentPeriodStartUTC;
            const periodEnd = stripeInvoice.period_end
              ? new Date(stripeInvoice.period_end * 1000)
              : currentPeriodEndUTC;
            const paymentDate = stripeInvoice.status_transitions?.paid_at
              ? new Date(stripeInvoice.status_transitions.paid_at * 1000)
              : new Date();
            const dueDate = stripeInvoice.due_date
              ? new Date(stripeInvoice.due_date * 1000)
              : new Date();

            // Create payment record in saas_payments
            await storage.createSaasPayment({
              organizationId: created.organizationId,
              subscriptionId: created.id,
              invoiceNumber: stripeInvoice.number || stripeInvoice.id,
              amount: ((stripeInvoice.amount_paid ?? stripeInvoice.total ?? 0) / 100).toFixed(2),
              currency: (stripeInvoice.currency || "gbp").toUpperCase(),
              paymentMethod: "stripe",
              paymentStatus: "completed",
              paymentDate: paymentDate,
              dueDate: dueDate,
              periodStart: periodStart,
              periodEnd: periodEnd,
              paymentProvider: "stripe",
              providerTransactionId: stripeInvoice.payment_intent?.toString() || stripeInvoice.charge?.toString(),
              metadata: {
                stripeInvoiceId: stripeInvoice.id,
                stripeSubscriptionId: stripeSubscription.id,
                stripeCheckoutSessionId: stripeInvoice.checkout_session?.toString(),
              },
              description: stripeInvoice.description || `Stripe invoice ${stripeInvoice.number || stripeInvoice.id}`,
              createdAt: new Date(),
              updatedAt: new Date(),
            });

            // Create invoice record in saas_invoices with Stripe invoice ID
            const lineItems = stripeInvoice.lines.data.map(line => ({
              description: line.description || "Subscription Service",
              quantity: line.quantity || 1,
              rate: line.price?.unit_amount ? line.price.unit_amount / 100 : (line.amount / 100),
              amount: line.amount / 100
            }));

            await storage.createInvoice({
              organizationId: created.organizationId,
              subscriptionId: created.id,
              invoiceNumber: stripeInvoice.number || `INV-${stripeInvoice.id}`,
              amount: ((stripeInvoice.total || 0) / 100).toFixed(2),
              currency: (stripeInvoice.currency || "gbp").toUpperCase(),
              status: "paid",
              issueDate: stripeInvoice.created ? new Date(stripeInvoice.created * 1000) : new Date(),
              dueDate: dueDate,
              paidDate: paymentDate,
              periodStart: periodStart,
              periodEnd: periodEnd,
              lineItems: lineItems,
              notes: `Stripe Invoice ID: ${stripeInvoice.id}. Thank you for your business.`
            });

            console.log(`[STRIPE] Created payment and invoice records for subscription ${created.id}, invoice ${stripeInvoice.id}`);
          }
        }
      } catch (invoiceErr: any) {
        console.error("[STRIPE] Failed to create payment/invoice records after subscription creation:", invoiceErr?.message || invoiceErr);
        // Don't throw - subscription was created successfully, payment/invoice records are secondary
      }
    }

    return created;
  }

  async function handleInvoiceSuccess(invoice: Stripe.Invoice) {
    const stripeSubscriptionId = typeof invoice.subscription === "string"
      ? invoice.subscription
      : invoice.subscription?.id;
    if (!stripeSubscriptionId) return;

    const subscription = await storage.getSaaSSubscriptionByStripeId(stripeSubscriptionId);
    if (!subscription) return;

    if (invoice.period_start) {
      await storage.updateSaaSSubscription(subscription.id, {
        status: "active",
        paymentStatus: "paid",
        currentPeriodStart: new Date(invoice.period_start * 1000),
        currentPeriodEnd: invoice.period_end ? new Date(invoice.period_end * 1000) : subscription.currentPeriodEnd,
      });
    } else {
      await storage.updateSaaSSubscription(subscription.id, {
        status: "active",
        paymentStatus: "paid",
      });
    }

    const periodStart = invoice.period_start ? new Date(invoice.period_start * 1000) : subscription.currentPeriodStart;
    const periodEnd = invoice.period_end ? new Date(invoice.period_end * 1000) : subscription.currentPeriodEnd;

    await storage.createSaasPayment({
      organizationId: subscription.organizationId,
      subscriptionId: subscription.id,
      invoiceNumber: invoice.number || invoice.id,
      amount: ((invoice.amount_paid ?? invoice.total ?? 0) / 100).toFixed(2),
      currency: (invoice.currency || "gbp").toUpperCase(),
      paymentMethod: "stripe",
      paymentStatus: "completed",
      paymentDate: invoice.status_transitions?.paid_at
        ? new Date(invoice.status_transitions.paid_at * 1000)
        : new Date(),
      dueDate: invoice.due_date ? new Date(invoice.due_date * 1000) : new Date(),
      periodStart,
      periodEnd,
      paymentProvider: "stripe",
      metadata: {
        stripeInvoiceId: invoice.id,
        stripeSubscriptionId,
        stripeCheckoutSessionId: invoice.checkout_session?.toString(),
      },
      description: invoice.description || `Stripe invoice ${invoice.number || invoice.id}`,
      createdAt: new Date(),
      updatedAt: new Date(),
    });

    // Also create formal SaaS Invoice record
    try {
      const lineItems = invoice.lines.data.map(line => ({
        description: line.description || "Subscription Service",
        quantity: line.quantity || 1,
        rate: line.amount / 100,
        amount: line.amount / 100
      }));

      const formalInvoice = await storage.createInvoice({
        organizationId: subscription.organizationId,
        subscriptionId: subscription.id,
        invoiceNumber: invoice.number || `INV-${invoice.id}`,
        amount: ((invoice.total || 0) / 100).toFixed(2),
        currency: (invoice.currency || "gbp").toUpperCase(),
        status: "paid",
        issueDate: invoice.created ? new Date(invoice.created * 1000) : new Date(),
        dueDate: invoice.due_date ? new Date(invoice.due_date * 1000) : new Date(),
        paidDate: invoice.status_transitions?.paid_at ? new Date(invoice.status_transitions.paid_at * 1000) : new Date(),
        periodStart,
        periodEnd,
        lineItems,
        notes: "Thank you for your business."
      });

      // Send Invoice Email
      const org = await storage.getOrganization(subscription.organizationId);
      if (org && org.email) {
        console.log(`[STRIPE] Sending invoice email to ${org.email}`);
        await emailService.sendSaaSInvoiceEmail(
          org.email,
          org.name,
          formalInvoice.invoiceNumber,
          formalInvoice.amount,
          formalInvoice.currency,
          formalInvoice.dueDate.toLocaleDateString(),
          lineItems
        );
      }
    } catch (invoiceErr) {
      console.error("[STRIPE] Failed to create formal invoice or send email:", invoiceErr);
    }
  }

  async function handleInvoiceFailure(invoice: Stripe.Invoice) {
    const stripeSubscriptionId = typeof invoice.subscription === "string"
      ? invoice.subscription
      : invoice.subscription?.id;
    if (!stripeSubscriptionId) return;

    const subscription = await storage.getSaaSSubscriptionByStripeId(stripeSubscriptionId);
    if (!subscription) return;

    await storage.updateSaaSSubscription(subscription.id, {
      status: "past_due",
      paymentStatus: "failed",
    });
  }

  const processStripeEvent = async (event: Stripe.Event) => {
    switch (event.type) {
      case "checkout.session.completed": {
        const session = event.data.object as Stripe.Checkout.Session;
        const packageId = Number(session.metadata?.packageId || session.metadata?.planId);
        const organizationId = Number(session.metadata?.organizationId);
        const isUpgrade = session.metadata?.isUpgrade === "true";
        const existingSubscriptionId = session.metadata?.existingSubscriptionId 
          ? Number(session.metadata.existingSubscriptionId) 
          : null;
        
        console.log("[STRIPE WEBHOOK] checkout.session.completed", {
          sessionId: session.id,
          organizationId,
          packageId,
          isUpgrade,
          existingSubscriptionId,
        });
        
        if (!packageId || !organizationId || !session.subscription) {
          break;
        }
        
        const stripeSubscription = await stripe.subscriptions.retrieve(session.subscription.toString());
        
        // If this is an upgrade and there's an existing subscription, cancel the old one
        if (isUpgrade && existingSubscriptionId) {
          try {
            const [existingSub] = await db
              .select()
              .from(saasSubscriptions)
              .where(eq(saasSubscriptions.id, existingSubscriptionId))
              .limit(1);
            
            if (existingSub?.stripeSubscriptionId && existingSub.stripeSubscriptionId !== stripeSubscription.id) {
              // Cancel the old subscription in Stripe
              await stripe.subscriptions.cancel(existingSub.stripeSubscriptionId);
              console.log(`✅ [WEBHOOK] Cancelled old subscription ${existingSub.stripeSubscriptionId}`);
            }
          } catch (cancelError: any) {
            console.error("⚠️ [WEBHOOK] Error cancelling old subscription:", cancelError.message);
            // Continue with new subscription activation even if old one fails to cancel
          }
        }
        
        // Activate the new/upgraded subscription
        await upsertSubscriptionFromStripe(stripeSubscription, organizationId, packageId);
        console.log(`✅ [WEBHOOK] Subscription activated for organization ${organizationId}, package ${packageId}`);
        break;
      }
      case "customer.subscription.updated": {
        const stripeSubscription = event.data.object as Stripe.Subscription;
        const existing = await storage.getSaaSSubscriptionByStripeId(stripeSubscription.id);
        if (existing) {
          await storage.updateSaaSSubscription(existing.id, {
            status: stripeSubscription.status,
            paymentStatus: ["active", "trialing"].includes(stripeSubscription.status) ? "paid" : "pending",
            currentPeriodStart: stripeSubscription.current_period_start
              ? new Date(stripeSubscription.current_period_start * 1000)
              : existing.currentPeriodStart,
            currentPeriodEnd: stripeSubscription.current_period_end
              ? new Date(stripeSubscription.current_period_end * 1000)
              : existing.currentPeriodEnd,
            cancelAtPeriodEnd: Boolean(stripeSubscription.cancel_at_period_end),
          });
        } else if (stripeSubscription.metadata?.packageId && stripeSubscription.metadata?.organizationId) {
          await upsertSubscriptionFromStripe(
            stripeSubscription,
            Number(stripeSubscription.metadata.organizationId),
            Number(stripeSubscription.metadata.packageId),
          );
        }
        break;
      }
      case "invoice.payment_succeeded": {
        const invoice = event.data.object as Stripe.Invoice;
        console.log("[STRIPE WEBHOOK] invoice.payment_succeeded", {
          invoiceId: invoice.id,
          subscriptionId: invoice.subscription,
        });
        await handleInvoiceSuccess(invoice);
        break;
      }
      case "invoice.payment_failed": {
        const invoice = event.data.object as Stripe.Invoice;
        await handleInvoiceFailure(invoice);
        break;
      }
      case "account.updated": {
        // Handle Stripe Connect account updates (e.g., after onboarding completion)
        const account = event.data.object as Stripe.Account;
        console.log("[STRIPE WEBHOOK] account.updated", {
          accountId: account.id,
          chargesEnabled: account.charges_enabled,
          payoutsEnabled: account.payouts_enabled,
          detailsSubmitted: account.details_submitted,
          capabilities: account.capabilities,
        });

        // Find organization by stripe_account_id
        const [organization] = await db
          .select()
          .from(organizations)
          .where(eq(organizations.stripeAccountId, account.id))
          .limit(1);

        if (organization) {
          // Check if account is ready: charges_enabled === true AND card_payments === "active"
          const cardPaymentsStatus = account.capabilities?.card_payments;
          const isAccountReady = account.charges_enabled === true && cardPaymentsStatus === 'active';

          // Update organization stripe status
          const newStatus = isAccountReady ? 'active' : 
                           (account.details_submitted ? 'pending' : 'incomplete');

          await db.update(organizations)
            .set({
              stripeStatus: newStatus,
              updatedAt: new Date(),
            })
            .where(eq(organizations.id, organization.id));

          console.log(`[STRIPE WEBHOOK] Updated organization ${organization.id} stripe status to ${newStatus}`, {
            accountId: account.id,
            chargesEnabled: account.charges_enabled,
            cardPayments: cardPaymentsStatus,
            isAccountReady,
          });
        } else {
          console.warn(`[STRIPE WEBHOOK] No organization found for Stripe account ${account.id}`);
        }
        break;
      }
      default:
        break;
    }
  };

  const stripeWebhookHandler = async (req: Request, res: Response) => {
    if (!stripe) {
      return res.status(500).send("Stripe not configured");
    }

    const signature = req.headers["stripe-signature"] as string | undefined;
    if (!signature) {
      return res.status(400).send("Missing Stripe signature");
    }

    if (!STRIPE_WEBHOOK_SECRET) {
      return res.status(500).send("Stripe webhook secret not configured");
    }

    let event: Stripe.Event;
    try {
      event = stripe.webhooks.constructEvent(req.body, signature, STRIPE_WEBHOOK_SECRET);
    } catch (error: any) {
      console.error("Stripe webhook signature verification failed:", error);
      return res.status(400).send("Webhook signature mismatch");
    }

    try {
      await processStripeEvent(event);
    } catch (error) {
      console.error("Error processing Stripe webhook:", error);
      return res.status(500).send("Failed to process webhook");
    }

    res.json({ received: true });
  };

  app.post("/api/stripe/webhooks", express.raw({ type: "application/json" }), stripeWebhookHandler);
  app.post("/api/stripe/webhook", express.raw({ type: "application/json" }), stripeWebhookHandler);
  app.post(
    "/api/stripe/webhook/:destinationId",
    express.raw({ type: "application/json" }),
    stripeWebhookHandler,
  );

