  // SaaS routes already registered above before tenant middleware

  const httpServer = createServer(app);

  console.log('[Socket.IO] Initializing Socket.IO server...');
  // Initialize Socket.IO server for real-time communication
  const io = new SocketIOServer(httpServer, {
    cors: {
      origin: "*", // In production, configure with specific origins
      methods: ["GET", "POST"],
      credentials: true
    },
    transports: ['websocket', 'polling'],
    pingTimeout: 60000,
    pingInterval: 25000
  });
  console.log('[Socket.IO] Socket.IO server initialized successfully');

  // Socket.IO connection handling
  const onlineUsers = new Map<string, Set<string>>(); // userId -> Set of socketIds

  const emitToOnlineUserIds = (
    targetUserIds: string[],
    event: string,
    payload: unknown,
    excludeSocketId?: string,
  ) => {
    const seen = new Set<string>();
    for (const userId of targetUserIds) {
      if (!userId || seen.has(userId)) continue;
      seen.add(userId);
      const socketIds = onlineUsers.get(userId);
      if (!socketIds) {
        console.warn(`[Socket.IO] ${event}: recipient offline:`, userId);
        continue;
      }
      for (const socketId of socketIds) {
        if (excludeSocketId && socketId === excludeSocketId) continue;
        io.to(socketId).emit(event, payload);
      }
    }
  };

  const collectIncomingCallRecipients = (callData: any): string[] => {
    const targets: string[] = [];
    if (typeof callData?.toUserId === "string" && callData.toUserId.trim()) {
      targets.push(callData.toUserId.trim());
    }
    if (typeof callData?.to === "string" && callData.to.trim()) {
      targets.push(callData.to.trim());
    }
    if (Array.isArray(callData?.toUserIds)) {
      for (const id of callData.toUserIds) {
        if (typeof id === "string" && id.trim()) targets.push(id.trim());
      }
    }
    return targets;
  };

  io.on('connection', (socket) => {
    console.log('[Socket.IO] Client connected:', socket.id);

    // Handle user registration
    socket.on('add_user', (data: { userId: string; deviceId?: string; organizationId?: number }) => {
      const { userId, deviceId, organizationId } = data;
      console.log('[Socket.IO] User registered:', userId, 'Socket:', socket.id, 'Organization:', organizationId);

      // Add user to online users map
      if (!onlineUsers.has(userId)) {
        onlineUsers.set(userId, new Set());
      }
      onlineUsers.get(userId)!.add(socket.id);

      // Store userId and organizationId on socket for easy lookup
      socket.data.userId = userId;
      socket.data.deviceId = deviceId;
      socket.data.organizationId = organizationId;

      // Join organization room for targeted currency updates
      if (organizationId) {
        const roomName = `org:${organizationId}`;
        socket.join(roomName);
        const roomSize = io.sockets.adapter.rooms.get(roomName)?.size || 0;
        console.log(`[Socket.IO] ✅ Socket ${socket.id} joined organization room: ${roomName} (${roomSize} clients in room)`);
      } else {
        console.warn(`[Socket.IO] ⚠️ User ${userId} registered without organizationId - will not receive room-based currency updates`);
      }

      // Broadcast updated online users list
      const onlineUserIds = Array.from(onlineUsers.keys());
      io.emit('online_users_update', { onlineUsers: onlineUserIds });
      console.log('[Socket.IO] Online users:', onlineUserIds.length);
    });

    // Handle call signaling
    socket.on('call-signal', (signal: any) => {
      console.log('[Socket.IO] Call signal:', signal.type, 'from', signal.from, 'to', signal.to);
      // Forward signal to the recipient
      io.emit('call-signal', signal);
    });

    // Handle incoming call — deliver only to intended recipient(s), not the caller
    socket.on('incoming-call', (callData: any) => {
      const recipients = collectIncomingCallRecipients(callData);
      console.log(
        '[Socket.IO] Incoming call from',
        callData?.fromUserId || callData?.from,
        'to',
        recipients,
      );
      if (recipients.length === 0) {
        console.warn('[Socket.IO] incoming-call ignored: no toUserId/to recipient');
        return;
      }
      emitToOnlineUserIds(recipients, 'incoming-call', callData, socket.id);
    });

    socket.on('call_accepted', (data: any) => {
      console.log('[Socket.IO] Call accepted:', data?.roomId, 'notify', data?.toUserId);
      const recipient = typeof data?.toUserId === 'string' ? data.toUserId.trim() : '';
      if (!recipient) {
        console.warn('[Socket.IO] call_accepted ignored: missing toUserId (caller)');
        return;
      }
      emitToOnlineUserIds([recipient], 'call_accepted', data, socket.id);
    });

    socket.on('call_declined', (data: any) => {
      console.log('[Socket.IO] Call declined:', data?.roomId, 'notify', data?.toUserId);
      const recipient = typeof data?.toUserId === 'string' ? data.toUserId.trim() : '';
      if (!recipient) {
        console.warn('[Socket.IO] call_declined ignored: missing toUserId (caller)');
        return;
      }
      emitToOnlineUserIds([recipient], 'call_declined', data, socket.id);
    });

    // Handle call end (hyphen: legacy)
    socket.on('call-ended', (data: any) => {
      console.log('[Socket.IO] Call ended:', data);
      io.emit('call-ended', data);
    });

    // Handle call end (underscore: telemedicine / LiveKit) – broadcast so other participant closes call UI
    socket.on('call_ended', (data: any) => {
      console.log('[Socket.IO] Call ended (call_ended):', data);
      io.emit('call_ended', data);
    });

    // Handle user registration (Averox-style)
    socket.on('register-user', (data: { userId: string; userName: string }) => {
      const { userId, userName } = data;
      console.log('[Socket.IO] User registered (Averox-style):', userId, userName);

      socket.data.userId = userId;
      socket.data.userName = userName;

      // Add to online users
      if (!onlineUsers.has(userId)) {
        onlineUsers.set(userId, new Set());
      }
      onlineUsers.get(userId)!.add(socket.id);

      // Broadcast updated online users
      const onlineUserIds = Array.from(onlineUsers.keys());
      io.emit('online_users_update', { onlineUsers: onlineUserIds });
    });

    // Handle disconnect
    socket.on('disconnect', () => {
      const userId = socket.data.userId;
      console.log('[Socket.IO] Client disconnected:', socket.id, 'User:', userId);

      if (userId && onlineUsers.has(userId)) {
        onlineUsers.get(userId)!.delete(socket.id);
        if (onlineUsers.get(userId)!.size === 0) {
          onlineUsers.delete(userId);
        }

        // Broadcast updated online users list
        const onlineUserIds = Array.from(onlineUsers.keys());
        io.emit('online_users_update', { onlineUsers: onlineUserIds });
      }
    });
  });

  // Store Socket.IO instance on app for use in routes
  app.set('io', io);

  // Start appointment reminder scheduler
  startAppointmentReminderScheduler();
  startVideoCallScheduler();

  // HTML Generator for PDF Reports
